        } else {
            enqueueMessage(chatId, text, replyMarkup)
        }
        answerBookingCallbackOrMessage(
            chatId = chatId,
            callbackQueryId = callbackQueryId,
            text = "Бронь подтверждена",
            fallbackMessage = "✅ ${formatBookingDisplayLabel(displayBooking)} подтверждена.",
