    private suspend fun sendGuestBookingReply(
        chatId: Long,
        from: User?,
        text: String,
        state: DialogState,
    ) {
        val userId = from?.id
        if (userId == null) {
            enqueueMessage(chatId, "Не удалось определить пользователя. Попробуйте /start.")
            return
        }
        val venueId = state.payload["venue_id"]?.toLongOrNull()
        val bookingId = state.payload["booking_id"]?.toLongOrNull()
        val guestUserId = state.payload["guest_user_id"]?.toLongOrNull()
        if (venueId == null || bookingId == null || guestUserId != userId) {
            dialogStateRepository.clear(chatId)
            enqueueMessage(chatId, "Не удалось отправить ответ. Откройте бронь заново.")
            return
        }
        if (text.trim() == "/cancel") {
            dialogStateRepository.clear(chatId)
            enqueueMessage(chatId, "Ответ отменён.")
            return
        }
        val replyText = text.trim()
        if (replyText.isBlank() || replyText.length > 1000) {
            enqueueMessage(chatId, "Ответ должен быть от 1 до 1000 символов.")
            return
        }
        val booking =
            try {
                guestBookingRepository.findActiveByGuest(
                    bookingId = bookingId,
                    venueId = venueId,
                    userId = userId,
                )
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return
            }
        if (booking == null) {
            dialogStateRepository.clear(chatId)
            enqueueMessage(chatId, "Бронь не найдена или уже неактуальна.")
            return
        }
        supportThreadRepository?.let { repository ->
            try {
                val thread =
                    repository.createOrFindBookingThread(
                        venueId = booking.venueId,
                        bookingId = booking.id,
                        guestUserId = booking.userId,
                        title = formatBookingDisplayLabel(booking),
                    )
                repository.addMessage(
                    threadId = thread.id,
                    authorUserId = userId,
                    authorRole = SupportMessageAuthorRole.GUEST,
                    source = SupportMessageSource.GUEST_BOT,
                    text = replyText,
                )
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return
            }
        }
        val venue =
            runCatching { venueRepository.findVenueById(venueId) }
                .getOrNull()
        val staffChatId = venue?.staffChatId
        if (staffChatId == null) {
            dialogStateRepository.clear(chatId)
            enqueueMessage(chatId, "✅ Ответ отправлен заведению.")
            return
        }
        val venueName = venue.name.takeIf { it.isNotBlank() } ?: "Заведение"
        val zoneId = resolveVenueZoneId(booking.venueId)
        val serviceDate = booking.displayDate ?: LocalDateTime.ofInstant(booking.scheduledAt, zoneId).toLocalDate()
        val guestDisplayName = loadGuestDisplayName(userId)?.takeIf { it.isNotBlank() } ?: "Гость"
        val staffText =
            buildString {
                append("💬 Ответ гостя по ").append(formatBookingDisplayLabel(booking))
                append('\n').append("Заведение: ").append(venueName)
                append('\n').append("Гость: ").append(guestDisplayName)
                append('\n').append("Смена: ").append(formatWeekdayFull(serviceDate.dayOfWeek))
                append(
                    '\n',
                ).append("Визит: ").append(formatStaffBookingVisitText(serviceDate, booking.scheduledAt, zoneId))
                append('\n').append("Текст: ").append(replyText)
            }
        enqueueGroupMessageWithoutReplyKeyboard(staffChatId, staffText)
        dialogStateRepository.clear(chatId)
        enqueueMessage(chatId, "✅ Ответ отправлен заведению.")
    }

    private fun isBookingReminderCallback(data: String?): Boolean =
        data?.startsWith("br_ok:") == true ||
            data?.startsWith("br_cancel_yes:") == true ||
            data?.startsWith("br_cancel:") == true ||
            data?.startsWith("br_reschedule:") == true ||
            data?.startsWith("br_msg:") == true ||
            data?.startsWith("br_back:") == true

    private suspend fun handleBookingReminderCallback(
        chatId: Long,
        user: User,
        sourceMessageId: Long?,
        callbackQueryId: String?,
        data: String?,
    ) {
        when {
            data?.startsWith("br_ok:") == true ->
                confirmBookingReminderAttendance(chatId, user, sourceMessageId, callbackQueryId, data)
            data?.startsWith("br_cancel_yes:") == true ->
                confirmBookingReminderCancel(chatId, user, callbackQueryId, data)
            data?.startsWith("br_cancel:") == true ->
                askBookingReminderCancel(chatId, user, sourceMessageId, callbackQueryId, data)
            data?.startsWith("br_reschedule:") == true ->
                rescheduleBookingFromReminder(chatId, user, callbackQueryId, data)
            data?.startsWith("br_msg:") == true ->
                promptBookingReminderMessage(chatId, user, callbackQueryId, data)
            data?.startsWith("br_back:") == true ->
                answerBookingCallbackOrMessage(
                    chatId = chatId,
                    callbackQueryId = callbackQueryId,
                    text = "Ок",
                    fallbackMessage = "Бронь остаётся активной.",
                )
        }
    }

    private suspend fun confirmBookingReminderAttendance(
        chatId: Long,
        user: User,
        sourceMessageId: Long?,
        callbackQueryId: String?,
        data: String,
    ) {
        val parsed =
            parseBookingReminderAttendanceData(data) ?: run {
                answerBookingCallbackOrMessage(
                    chatId = chatId,
                    callbackQueryId = callbackQueryId,
                    text = "Не удалось подтвердить",
                    fallbackMessage = "Не удалось подтвердить бронь. Попробуйте ещё раз.",
                    showAlert = true,
                )
                return
            }
        val (bookingId, reminderId) = parsed
        if (reminderId == null) {
            answerBookingCallbackOrMessage(
                chatId = chatId,
                callbackQueryId = callbackQueryId,
                text = "Время брони изменилось. Откройте актуальную бронь.",
                fallbackMessage = "Время брони изменилось. Откройте актуальную бронь.",
                showAlert = true,
            )
            return
        }
        val result =
            try {
                guestBookingRepository.confirmGuestAttendanceFromReminder(
                    bookingId = bookingId,
                    userId = user.id,
                    reminderId = reminderId,
                )
            } catch (e: DatabaseUnavailableException) {
                answerBookingCallbackOrMessage(
                    chatId = chatId,
                    callbackQueryId = callbackQueryId,
                    text = "База недоступна",
                    fallbackMessage = "База недоступна, попробуйте позже.",
                    showAlert = true,
                )
                return
            }
        when (result.status) {
            GuestAttendanceConfirmationStatus.APPLIED -> {
                val booking = result.booking ?: return
                notifyStaffChatAboutGuestReminderConfirmation(
                    booking = booking,
                    guestUserId = user.id,
                    scheduleVersionEpochSeconds = result.scheduleVersionEpochSeconds,
                )
                updateBookingReminderAttendanceMessage(
                    chatId = chatId,
                    sourceMessageId = sourceMessageId,
                    booking = booking,
                    scheduleVersionEpochSeconds = result.scheduleVersionEpochSeconds,
                )
                answerBookingCallbackOrMessage(
                    chatId = chatId,
                    callbackQueryId = callbackQueryId,
                    text = "Спасибо, отметили, что вы придёте.",
                    fallbackMessage = "Спасибо, отметили, что вы придёте.",
                )
            }
            GuestAttendanceConfirmationStatus.ALREADY_CONFIRMED -> {
                result.booking?.let { booking ->
                    updateBookingReminderAttendanceMessage(
                        chatId = chatId,
                        sourceMessageId = sourceMessageId,
                        booking = booking,
                        scheduleVersionEpochSeconds = result.scheduleVersionEpochSeconds,
                    )
                }
                answerBookingCallbackOrMessage(
                    chatId = chatId,
                    callbackQueryId = callbackQueryId,
                    text = "Вы уже подтвердили визит.",
                    fallbackMessage = "Вы уже подтвердили визит.",
                )
            }
            GuestAttendanceConfirmationStatus.STALE -> {
                if (sourceMessageId != null) {
                    enqueueEditMessage(
                        chatId = chatId,
                        messageId = sourceMessageId,
                        text = "Время брони изменилось. Откройте актуальную бронь.",
                        replyMarkup = null,
                    )
                }
                answerBookingCallbackOrMessage(
                    chatId = chatId,
                    callbackQueryId = callbackQueryId,
                    text = "Время брони изменилось. Откройте актуальную бронь.",
                    fallbackMessage = "Время брони изменилось. Откройте актуальную бронь.",
                    showAlert = true,
                )
            }
            GuestAttendanceConfirmationStatus.TERMINAL,
            GuestAttendanceConfirmationStatus.NOT_ELIGIBLE,
            GuestAttendanceConfirmationStatus.NOT_FOUND,
            -> {
                if (sourceMessageId != null && result.status == GuestAttendanceConfirmationStatus.TERMINAL) {
                    enqueueEditMessage(
                        chatId = chatId,
                        messageId = sourceMessageId,
                        text = "Бронь уже неактуальна.",
                        replyMarkup = null,
                    )
                }
                answerBookingCallbackOrMessage(
                    chatId = chatId,
                    callbackQueryId = callbackQueryId,
                    text = "Бронь неактуальна",
                    fallbackMessage = "Бронь не найдена или уже неактуальна.",
                    showAlert = true,
                )
            }
        }
    }

    private suspend fun updateBookingReminderAttendanceMessage(
        chatId: Long,
        sourceMessageId: Long?,
        booking: com.hookah.platform.backend.miniapp.guest.db.BookingRecord,
        scheduleVersionEpochSeconds: Long?,
    ) {
        if (sourceMessageId == null) return
        val displayBooking = withEffectiveBookingDeadline(booking)
        val zoneId = resolveVenueZoneId(displayBooking.venueId)
        val venueName = venueRepository.findVenueById(displayBooking.venueId)?.name ?: "Заведение"
        enqueueEditMessage(
            chatId = chatId,
            messageId = sourceMessageId,
            text = buildBookingReminderAttendanceConfirmedText(displayBooking, venueName, zoneId),
            replyMarkup = TelegramKeyboards.inlineBookingReminderConfirmedActions(displayBooking.id),
            dedupeKey =
                "booking-reminder-confirm-edit:${displayBooking.id}:" +
                    "${scheduleVersionEpochSeconds ?: "current"}:$sourceMessageId",
        )
    }

    private fun buildBookingReminderAttendanceConfirmedText(
        booking: com.hookah.platform.backend.miniapp.guest.db.BookingRecord,
        venueName: String,
        zoneId: ZoneId,
    ): String {
        val visitText = LocalDateTime.ofInstant(booking.scheduledAt, zoneId).format(bookingReminderDateTimeFormatter)
        val deadlineText =
            booking.arrivalDeadlineAt
                ?.let { LocalDateTime.ofInstant(it, zoneId).format(bookingTimeFormatter) }
        return buildString {
            append("Напоминаем о брони")
            append("\n\nМесто: ").append(venueName)
            append('\n').append(formatBookingDisplayLabel(booking))
            append("\nДата и время: ").append(visitText)
            append("\nГостей: ").append(booking.partySize ?: "не указано")
            deadlineText?.let { append("\nДержим стол до ").append(it).append('.') }
            append("\n\n✅ Вы подтвердили, что придёте.")
        }
    }

    private fun parseBookingReminderAttendanceData(data: String): Pair<Long, Long?>? {
        if (!data.startsWith("br_ok:")) return null
        val parts = data.removePrefix("br_ok:").split(':')
        val bookingId = parts.getOrNull(0)?.toLongOrNull() ?: return null
        val reminderId = parts.getOrNull(1)?.toLongOrNull()
        return bookingId to reminderId
    }

    private suspend fun rescheduleBookingFromReminder(
        chatId: Long,
        user: User,
        callbackQueryId: String?,
        data: String,
    ) {
        val booking =
            loadActiveGuestBookingFromReminder(
                chatId = chatId,
                callbackQueryId = callbackQueryId,
                userId = user.id,
                data = data,
                prefix = "br_reschedule:",
            ) ?: return
        val venue = loadCatalogVenueById(chatId, booking.venueId) ?: return
        botBookingEditContexts[chatId] =
            BotBookingEditContext(
                bookingId = booking.id,
                venueId = booking.venueId,
                userId = user.id,
            )
        renderBotVenueBookingDatePicker(
            chatId = chatId,
            venue = venue,
            offset = 0,
            prompt =
                "Выберите новую дату для " +
                    "${formatBookingDisplayLabel(booking).replaceFirstChar { it.lowercase(Locale.ROOT) }}.",
        )
        answerBookingCallbackOrMessage(
            chatId = chatId,
            callbackQueryId = callbackQueryId,
            text = "Выберите новое время",
            fallbackMessage = "Выберите новую дату и время брони.",
        )
    }

    private suspend fun askBookingReminderCancel(
        chatId: Long,
        user: User,
        sourceMessageId: Long?,
        callbackQueryId: String?,
        data: String,
    ) {
        val booking = loadActiveGuestBookingFromReminder(chatId, callbackQueryId, user.id, data, "br_cancel:") ?: return
        val text = "Отменить ${formatBookingDisplayLabel(booking)}?"
        val replyMarkup = TelegramKeyboards.inlineBookingReminderCancelConfirm(booking.id)
        if (sourceMessageId != null) {
            enqueueEditMessage(chatId, sourceMessageId, text, replyMarkup)
        } else {
            enqueueMessage(chatId, text, replyMarkup)
        }
        answerBookingCallbackOrMessage(
            chatId = chatId,
            callbackQueryId = callbackQueryId,
            text = "Подтвердите отмену",
            fallbackMessage = "Подтвердите отмену брони.",
        )
    }

    private suspend fun confirmBookingReminderCancel(
        chatId: Long,
        user: User,
        callbackQueryId: String?,
        data: String,
    ) {
        val booking =
            loadActiveGuestBookingFromReminder(
                chatId,
                callbackQueryId,
                user.id,
                data,
                "br_cancel_yes:",
            ) ?: return
        val canceled =
            try {
                guestBookingRepository.cancelByGuest(
                    bookingId = booking.id,
                    venueId = booking.venueId,
                    userId = user.id,
                )
            } catch (e: DatabaseUnavailableException) {
                answerBookingCallbackOrMessage(
                    chatId = chatId,
                    callbackQueryId = callbackQueryId,
                    text = "База недоступна",
                    fallbackMessage = "База недоступна, попробуйте позже.",
                    showAlert = true,
                )
                return
            }
        if (canceled == null) {
            answerBookingCallbackOrMessage(
                chatId = chatId,
                callbackQueryId = callbackQueryId,
                text = "Бронь неактуальна",
                fallbackMessage = "Не удалось отменить бронь. Возможно, она уже неактуальна.",
                showAlert = true,
            )
            return
        }
        enqueueMessage(chatId, "✅ ${formatBookingDisplayLabel(canceled)} отменена.")
        notifyStaffChatAboutBooking(
            BookingStaffNotification(
                venueId = canceled.venueId,
                bookingId = canceled.id,
                event = BookingStaffNotificationEvent.CANCELLED,
                scheduledAtText =
                    formatBookingInstantForStaff(
                        canceled.scheduledAt,
                        resolveVenueZoneId(canceled.venueId),
                    ),
                partySize = canceled.partySize,
                comment = canceled.comment,
                displayNumber = canceled.displayNumber,
