        zoneId: ZoneId = ZoneId.systemDefault(),
    ): String {
        val number = displayNumber ?: return "Заказ #$orderId"
        val suffix =
            when (displayDate) {
                null -> ""
                LocalDate.now(zoneId) -> " · сегодня"
                else -> " · ${displayDate.format(bookingDateConfirmFormatter)}"
