    private suspend fun updateVenuePromotionRuleTarget(
        chatId: Long,
        userId: Long,
        data: String,
    ) {
        val parsed = parseVenuePromotionRuleTargetEditData(data)
        if (parsed == null) {
            enqueueMessage(chatId, "Не удалось обновить цель правила. Попробуйте ещё раз.")
            return
