    private suspend fun validatePromotionText(
        chatId: Long,
        text: String,
        label: String,
        maxLength: Int,
        allowBlank: Boolean = false,
        replyMarkup: ReplyMarkup? = null,
    ): String? {
        val trimmed = text.trim()
        if (!allowBlank && trimmed.isBlank()) {
            enqueueMessage(chatId, "$label не должно быть пустым.", replyMarkup)
            return null
        }
        if (trimmed.length > maxLength) {
            enqueueMessage(chatId, "$label слишком длинное. Максимум: $maxLength символов.", replyMarkup)
            return null
        }
        return trimmed.takeIf { it.isNotBlank() }
    }

    private fun venuePromotionTextInputActions(
        venueId: Long,
        promotionId: Long?,
    ): InlineKeyboardMarkup =
        if (promotionId == null) {
            TelegramKeyboards.inlineVenuePromotionCreateProgressActions(venueId)
        } else {
            TelegramKeyboards.inlineVenuePromotionEditPromptActions(venueId, promotionId)
        }

    private fun venuePromotionMediaInputActions(
        venueId: Long,
        promotionId: Long?,
    ): InlineKeyboardMarkup = venuePromotionTextInputActions(venueId, promotionId)

    private fun isVenuePromotionDialogState(state: DialogStateType): Boolean =
        state == DialogStateType.VENUE_PROMOTION_WAIT_TITLE ||
            state == DialogStateType.VENUE_PROMOTION_WAIT_DESCRIPTION ||
            state == DialogStateType.VENUE_PROMOTION_WAIT_TERMS ||
            state == DialogStateType.VENUE_PROMOTION_WAIT_STARTS_AT ||
            state == DialogStateType.VENUE_PROMOTION_WAIT_ENDS_AT ||
            state == DialogStateType.VENUE_PROMOTION_WAIT_MEDIA ||
            state == DialogStateType.VENUE_PROMOTION_RULE_WAIT_PERCENT ||
            state == DialogStateType.VENUE_PROMOTION_RULE_WAIT_START_TIME ||
            state == DialogStateType.VENUE_PROMOTION_RULE_WAIT_END_TIME

    private suspend fun cancelVenuePromotionDialog(
        chatId: Long,
        state: DialogState,
    ) {
        dialogStateRepository.clear(chatId)
        enqueueMessage(chatId, "Редактирование акции отменено.")
    }

    private suspend fun showAddVenueEntry(
        chatId: Long,
        from: User?,
    ) {
        val userId = from?.id ?: chatContextRepository.get(chatId)?.userId
        if (userId == null) {
            enqueueMessage(chatId, "Не удалось определить пользователя. Нажмите /start и попробуйте снова.")
            return
        }
        val pending =
            try {
                venueConnectionRequestRepository.findActiveUnlinkedByUser(userId)
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return
            }
        if (pending != null) {
            showApplicantActiveVenueConnectionRequest(chatId, pending)
            return
        }
        dialogStateRepository.set(chatId, DialogState(DialogStateType.VENUE_CONNECT_WAIT_NAME))
        enqueueMessage(
            chatId,
            "Заявка на подключение кальянной.\nВведите название кальянной.",
        )
    }

    private suspend fun proceedVenueConnectionName(
        chatId: Long,
        text: String,
        state: DialogState,
    ) {
        val venueName = normalizeVenueConnectionRequiredField(text, maxLength = 200)
        if (venueName == null) {
            enqueueMessage(chatId, "Введите корректное название кальянной (до 200 символов).")
            return
        }
        val editingRequestId = state.payload["editing_request_id"]
        val payload =
            buildMap {
                put("venue_name", venueName)
                if (!editingRequestId.isNullOrBlank()) {
                    put("editing_request_id", editingRequestId)
                }
            }
        dialogStateRepository.set(
            chatId,
            DialogState(
                DialogStateType.VENUE_CONNECT_WAIT_CITY,
                payload = payload,
            ),
        )
        enqueueMessage(chatId, "Введите город.")
    }

    private suspend fun proceedVenueConnectionCity(
        chatId: Long,
        from: User?,
        text: String,
        state: DialogState,
    ) {
        val venueName = state.payload["venue_name"]
        val editingRequestId = state.payload["editing_request_id"]
        if (venueName.isNullOrBlank()) {
            dialogStateRepository.clear(chatId)
            enqueueMessage(chatId, "Не удалось продолжить заявку. Нажмите «🤝 Добавить свою кальянную» ещё раз.")
            return
        }
        val city = normalizeVenueConnectionRequiredField(text, maxLength = 120)
        if (city == null) {
            enqueueMessage(chatId, "Введите корректный город (до 120 символов).")
            return
        }
        val username = from?.username?.trim()?.removePrefix("@")?.takeIf { it.isNotBlank() }
        if (username != null) {
            val baseContact = "@$username"
            val payload =
                buildMap {
                    put("venue_name", venueName)
                    put("city", city)
                    put("base_contact", baseContact)
                    if (!editingRequestId.isNullOrBlank()) {
                        put("editing_request_id", editingRequestId)
                    }
                }
            dialogStateRepository.set(
                chatId,
                DialogState(
                    DialogStateType.VENUE_CONNECT_WAIT_CONTACT_CHOICE,
                    payload = payload,
                ),
            )
            enqueueMessage(
                chatId,
                "Контакт для связи: $baseContact\nХотите добавить дополнительный контакт?",
                TelegramKeyboards.inlineVenueConnectionContactChoice(),
            )
            return
        }
        dialogStateRepository.set(
            chatId,
            DialogState(
                DialogStateType.VENUE_CONNECT_WAIT_CONTACT,
                payload =
                    buildMap {
                        put("venue_name", venueName)
                        put("city", city)
                        if (!editingRequestId.isNullOrBlank()) {
                            put("editing_request_id", editingRequestId)
                        }
                    },
            ),
        )
        enqueueMessage(chatId, "Укажите контакт для связи: телефон, email или другой удобный способ связи.")
    }

