        venueId: Long,
    ) {
        val hasAccess =
            runCatching { venueAccessRepository.hasVenueAdminOrOwner(userId, venueId) }
                .onFailure { logBestEffort("check venue owner access on publish readiness", it) }
                .getOrDefault(false)
        if (!hasAccess) {
