    private suspend fun acceptStaffInvite(
        chatId: Long,
        userId: Long,
        data: String,
    ) {
        val inviteCode = parseStaffInviteCodeFromCallback(data, "staff_invite_accept:")
        if (inviteCode == null) {
            enqueueMessage(chatId, "Не удалось принять приглашение. Попробуйте ещё раз.")
            return
        }
        val result =
            staffInviteRepository.acceptInvite(
                code = inviteCode,
                userId = userId,
                createMember = createMember@{ connection, venueId, role, invitedByUserId ->
                    if (role.equals("OWNER", ignoreCase = true)) {
                        when (
                            venueOwnerAccountRepository.prepareOwnerAssignmentInTransaction(
                                connection = connection,
                                venueId = venueId,
                                ownerUserId = userId,
                                defaultLimit = 1,
                                updatedByUserId = invitedByUserId,
                            )
                        ) {
                            is OwnerAccountAssignmentPreparationResult.Success -> Unit
                            else -> return@createMember null
                        }
                    }
                    venueStaffRepository.createMemberInTransaction(
                        connection = connection,
                        venueId = venueId,
                        userId = userId,
                        role = role,
                        invitedByUserId = invitedByUserId,
                    )
                },
            )
        when (result) {
            is StaffInviteAcceptResult.Success -> {
                appendOwnerInviteAcceptAuditBestEffort(auditLogRepository, result, logger)
                enqueueMessage(
                    chatId,
                    buildStaffInviteAcceptedText(result),
                    resolvePostInviteReplyMarkup(chatId, userId),
                )
            }
            StaffInviteAcceptResult.InvalidOrExpired ->
                enqueueMessage(chatId, "Приглашение недействительно или истекло.")
            StaffInviteAcceptResult.DatabaseError ->
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
        }
    }

    private suspend fun declineStaffInvite(
        chatId: Long,
        userId: Long,
        data: String,
    ) {
        val inviteCode = parseStaffInviteCodeFromCallback(data, "staff_invite_decline:")
        if (inviteCode == null) {
