    ) {
        val parsed = parseOwnerVenueMenuItemData(data, "owner_venue_item_flavors_norm_confirm:")
        if (parsed == null) {
            enqueueMessage(chatId, "Не удалось привести варианты к базовым профилям. Попробуйте ещё раз.")
