        venueId: Long,
    ): StaffChatStatus? {
        val status =
            try {
                venueRepository.findStaffChatStatus(venueId)
            } catch (e: CancellationException) {
                throw e
            } catch (e: Exception) {
                logBestEffort("load staff chat status", e)
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
