    private suspend fun handleStaffChatOrderBatchAction(
        chatId: Long,
        messageId: Long?,
        callbackQueryId: String,
        user: User,
        data: String,
        expectedStatus: OrderBatchStatus,
        nextStatus: OrderBatchStatus,
    ) {
        try {
            handleStaffChatOrderBatchActionUnsafe(
                chatId = chatId,
                messageId = messageId,
                callbackQueryId = callbackQueryId,
                user = user,
                data = data,
                expectedStatus = expectedStatus,
                nextStatus = nextStatus,
            )
        } catch (e: CancellationException) {
            throw e
        } catch (e: Exception) {
            logger.warn("staff chat order action failed: {}", sanitizeTelegramForLog(e.message))
            logger.debugTelegramException(e) { "staff chat order action exception" }
            enqueueCallbackAnswer(chatId, callbackQueryId, text = "Не удалось выполнить действие", showAlert = true)
        }
    }

    private suspend fun handleStaffChatOrderBatchActionUnsafe(
        chatId: Long,
        messageId: Long?,
        callbackQueryId: String,
        user: User,
        data: String,
        expectedStatus: OrderBatchStatus,
        nextStatus: OrderBatchStatus,
    ) {
        val prefix =
            when (nextStatus) {
                OrderBatchStatus.ACCEPTED -> "sc_ob_a:"
                OrderBatchStatus.DELIVERED -> "sc_ob_d:"
                else -> ""
            }
        val parsed = parseStaffChatActionData(data, prefix)
        if (parsed == null) {
            enqueueCallbackAnswer(chatId, callbackQueryId, text = "Не удалось выполнить действие", showAlert = true)
            return
        }
        val (venueId, batchId) = parsed
        val role = resolveVenueRoleForStaffChatAction(user.id, venueId)
        if (role == null) {
            enqueueCallbackAnswer(chatId, callbackQueryId, text = "Нет доступа", showAlert = true)
            return
        }
        val result =
            try {
                venueOrdersRepository.updateBatchStatus(
                    venueId = venueId,
                    batchId = batchId,
                    expectedCurrentStatus = expectedStatus,
                    nextStatus = nextStatus,
                    actor = OrderActionActor(userId = user.id, role = role.toVenueRole()),
                )
            } catch (e: DatabaseUnavailableException) {
                enqueueCallbackAnswer(chatId, callbackQueryId, text = "База недоступна", showAlert = true)
                return
            }
        if (result == null) {
            enqueueCallbackAnswer(chatId, callbackQueryId, text = "Заказ не найден", showAlert = true)
            return
        }
        if (!result.applied) {
            if (editClosedStaffChatOrderBatchMessageIfNeeded(chatId, messageId, venueId, result.orderId, batchId)) {
                enqueueCallbackAnswer(chatId, callbackQueryId, text = "Счёт уже закрыт.")
                return
            }
            refreshStaffChatOrderBatchMessage(chatId, messageId, venueId, result, batchId)
            enqueueCallbackAnswer(chatId, callbackQueryId, text = "Уже обработано")
            return
        }
        val actor = formatStaffChatActionActor(user)
        val statusLine =
            when (nextStatus) {
                OrderBatchStatus.ACCEPTED -> "✅ Принял: $actor"
                OrderBatchStatus.DELIVERED -> "✅ Доставлено: $actor"
                else -> "✅ Обновлено: $actor"
            }
        val replyMarkup =
            buildStaffChatLiveOrderActions(venueId = venueId, orderId = result.orderId)
                ?: TelegramKeyboards.inlineStaffChatOrderActions(
                    venueId = venueId,
                    orderId = result.orderId,
                    batchId = batchId,
                    status = nextStatus.toWorkflow(),
                    webAppUrl = venueMiniAppUrl(venueId),
                    batchLabel = null,
                )
        notifyGuestAboutStaffChatBatchStatusChange(
            venueId = venueId,
            orderId = result.orderId,
            batchId = batchId,
            nextStatus = nextStatus.toWorkflow(),
        )
        editStaffChatOrderBatchMessage(
            chatId = chatId,
            messageId = messageId,
            venueId = venueId,
            orderId = result.orderId,
            batchId = batchId,
            statusLine = statusLine,
            replyMarkup = replyMarkup,
        )
        enqueueCallbackAnswer(chatId, callbackQueryId, text = "Готово")
    }

    private suspend fun handleStaffChatShiftExtensionDecision(
        chatId: Long,
        messageId: Long?,
        callbackQueryId: String,
        user: User,
        data: String,
        approve: Boolean,
    ) {
        try {
            handleStaffChatShiftExtensionDecisionUnsafe(
                chatId = chatId,
                messageId = messageId,
                callbackQueryId = callbackQueryId,
                user = user,
                data = data,
                approve = approve,
            )
        } catch (e: CancellationException) {
            throw e
        } catch (e: Exception) {
            logger.warn("staff chat shift extension action failed: {}", sanitizeTelegramForLog(e.message))
            logger.debugTelegramException(e) { "staff chat shift extension action exception" }
            enqueueCallbackAnswer(chatId, callbackQueryId, text = "Не удалось выполнить действие", showAlert = true)
        }
    }

    private suspend fun handleStaffChatShiftExtensionDecisionUnsafe(
        chatId: Long,
        messageId: Long?,
        callbackQueryId: String,
        user: User,
        data: String,
        approve: Boolean,
    ) {
        val parsed = parseStaffChatActionData(data, if (approve) "sc_se_a:" else "sc_se_r:")
        if (parsed == null) {
            enqueueCallbackAnswer(chatId, callbackQueryId, text = "Не удалось выполнить действие", showAlert = true)
            return
        }
        val (venueId, requestId) = parsed
        val role = resolveVenueRoleForStaffChatAction(user.id, venueId)
        if (role == null || !role.hasPermission(VenuePermission.SHIFT_EXTENSION_CONFIRM)) {
            enqueueCallbackAnswer(chatId, callbackQueryId, text = "Нет доступа", showAlert = true)
            return
        }
        val result =
            try {
                if (approve) {
                    shiftExtensionRepository.approveRequest(
                        venueId = venueId,
                        requestId = requestId,
                        actorUserId = user.id,
                    )
                } else {
                    shiftExtensionRepository.rejectRequest(
                        venueId = venueId,
                        requestId = requestId,
                        actorUserId = user.id,
                        reasonText = null,
                    )
                }
            } catch (e: DatabaseUnavailableException) {
                enqueueCallbackAnswer(chatId, callbackQueryId, text = "База недоступна", showAlert = true)
                return
            } catch (e: NotFoundException) {
                enqueueCallbackAnswer(chatId, callbackQueryId, text = "Запрос не найден", showAlert = true)
                return
            } catch (e: InvalidInputException) {
                enqueueCallbackAnswer(chatId, callbackQueryId, text = "Уже обработано")
                return
            }
        refreshStaffChatShiftExtensionMessage(
            chatId = chatId,
            messageId = messageId,
            venueId = venueId,
            orderId = result.orderId,
        )
        val answer =
            when {
                !result.applied -> "Уже обработано"
                approve -> "Продление подтверждено"
                else -> "Продление отклонено"
            }
        enqueueCallbackAnswer(chatId, callbackQueryId, text = answer)
    }

    private suspend fun refreshStaffChatShiftExtensionMessage(
        chatId: Long,
        messageId: Long?,
        venueId: Long,
        orderId: Long,
    ) {
        val detail =
            try {
                venueOrdersRepository.loadOrderDetail(venueId = venueId, orderId = orderId)
            } catch (e: DatabaseUnavailableException) {
                return
            } ?: return
        val batchId = staffChatActionBatchId(detail)
        editStaffChatOrderBatchMessage(
            chatId = chatId,
            messageId = messageId,
            venueId = venueId,
            orderId = orderId,
            batchId = batchId,
            statusLine = staffChatOrderCurrentStatusLine(detail.status),
            replyMarkup = staffChatLiveOrderActions(venueId = venueId, detail = detail),
        )
    }

