            .sortedWith(compareBy({ it.createdAt }, { it.batchId }))
            .filter { batch -> !isCancelledVenueOrderBatch(batch) }
            .flatMap { batch ->
                batch.items
                    .filter { item -> isActiveBillItem(item) }
                    .map { item -> batch to item }
            }

