    private fun buildManagerVenueStaffRootText(members: List<VenueAccessRepository.VenueMemberSummary>): String =
        buildString {
            append("👥 Персонал")
            append("\n\n")
            if (members.any { it.role.uppercase(Locale.ROOT) == "OWNER" }) {
                append("Владелец: назначен")
                append("\n\n")
            }
            val staffMembers = members.filter { it.role.uppercase(Locale.ROOT) == "STAFF" }
            if (staffMembers.isEmpty()) {
                append("Staff / оператор смены пока не добавлен.")
            } else {
                append("Операционная команда:")
                staffMembers.forEach { member ->
                    append("\n• ")
                    append(formatOwnerVenueStaffMember(member))
                    append(" — ")
                    append(humanizeOwnerVenueStaffRole(member.role))
                }
            }
        }

    private fun formatOwnerVenueStaffMember(member: VenueAccessRepository.VenueMemberSummary): String {
        val username = member.username?.trim().orEmpty()
        if (username.isNotBlank()) {
            return "@$username"
        }
        val firstName = member.firstName?.trim().orEmpty()
        val lastName = member.lastName?.trim().orEmpty()
        val fullName = listOf(firstName, lastName).filter { it.isNotBlank() }.joinToString(" ")
        if (fullName.isNotBlank()) {
            return fullName
        }
        return "ID ${member.userId}"
    }

