    private suspend fun showGuestShiftExtension(
        chatId: Long,
        sourceMessageId: Long? = null,
    ) {
        val context = resolveGuestBotShiftExtensionContext(chatId) ?: return
        val text = buildGuestShiftExtensionText(context)
        val canRequest = context.canSubmitRequest
        val replyMarkup = TelegramKeyboards.inlineGuestShiftExtensionActions(canRequest)
        if (sourceMessageId != null) {
            enqueueEditMessage(chatId, sourceMessageId, text, replyMarkup)
        } else {
            enqueueMessage(chatId, text, replyMarkup)
        }
    }

    private suspend fun createGuestShiftExtensionRequest(
        chatId: Long,
        sourceMessageId: Long?,
    ) {
        val context = resolveGuestBotShiftExtensionContext(chatId)
        if (context == null) {
            return
        }
        if (!context.canSubmitRequest) {
            val text = buildGuestShiftExtensionText(context)
            if (sourceMessageId != null) {
                enqueueEditMessage(
                    chatId = chatId,
                    messageId = sourceMessageId,
                    text = text,
                    replyMarkup = TelegramKeyboards.inlineGuestShiftExtensionActions(false),
                )
            } else {
                enqueueMessage(chatId, text, TelegramKeyboards.inlineGuestShiftExtensionActions(false))
            }
            return
        }
        val activeOrder = context.order ?: return
        val record =
            try {
                shiftExtensionRepository.createPendingRequest(
                    CreateShiftExtensionRequestCommand(
                        venueId = context.resolved.table.venueId,
                        tableSessionId = context.tableSession.id,
                        tableId = context.resolved.table.tableId,
                        tabId = context.tab.id,
                        orderId = activeOrder.id,
                        requestedByUserId = context.resolved.userId,
                        currentOrderableUntil = context.tableSession.expiresAt,
                        idempotencyKey =
                            sourceMessageId?.let { messageId ->
                                "guest-bot-shift-extension:$chatId:$messageId"
                            },
                        comment = null,
                    ),
                )
            } catch (e: CancellationException) {
                throw e
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return
            } catch (e: InvalidInputException) {
                showGuestShiftExtension(chatId, sourceMessageId)
                return
            } catch (e: NotFoundException) {
                enqueueMessage(chatId, "Активный заказ не найден.")
                return
            }
        notifyStaffChatAboutShiftExtensionRequest(
            venueId = context.resolved.table.venueId,
            orderId = record.orderId,
        )
        val pendingText = guestShiftExtensionPendingText()
        if (sourceMessageId != null) {
            enqueueEditMessage(
                chatId = chatId,
                messageId = sourceMessageId,
                text = pendingText,
                replyMarkup = TelegramKeyboards.inlineGuestShiftExtensionActions(false),
            )
        } else {
            enqueueMessage(chatId, pendingText, TelegramKeyboards.inlineGuestShiftExtensionActions(false))
        }
    }

    private suspend fun resolveGuestBotShiftExtensionContext(chatId: Long): GuestBotShiftExtensionContext? {
        val resolved = resolveGuestContext(chatId) ?: return null
        val tableSession =
            resolveCurrentTableSession(chatId, resolved) ?: run {
                enqueueMessage(chatId, "Сессия стола истекла. Отсканируйте QR ещё раз.")
                return null
            }
        val tab = resolveCurrentBotTab(chatId, resolved) ?: return null
        val settings =
            try {
                shiftExtensionRepository.getSettings(resolved.table.venueId)
            } catch (e: CancellationException) {
                throw e
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return null
            }
        val pending =
            try {
                shiftExtensionRepository.findPendingRequest(
                    tableSessionId = tab.tableSessionId,
                    tabId = tab.id,
                )
            } catch (e: CancellationException) {
                throw e
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return null
            }
        val order =
            try {
                ordersRepository.findActiveOrderSummaryForTab(
                    tableSessionId = tab.tableSessionId,
                    tabId = tab.id,
                )
            } catch (e: CancellationException) {
                throw e
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return null
            }
        return GuestBotShiftExtensionContext(
            resolved = resolved,
            tableSession = tableSession,
            tab = tab,
            order = order,
            settings = settings,
            pending = pending,
        )
    }

    private fun buildGuestShiftExtensionText(context: GuestBotShiftExtensionContext): String =
        when {
            context.pending != null -> guestShiftExtensionPendingText()
            !context.settings.enabled ->
                "Продление работы заведения\n\nПродление сейчас недоступно."
            context.settings.priceMinor == null ->
                "Продление работы заведения\n\n" +
                    "Продление сейчас недоступно, цена или длительность не настроены."
            context.order == null ->
                "Продление работы заведения\n\n" +
                    "Продление доступно после оформления заказа за столом."
            else ->
                "Продление работы заведения\n\n" +
                    "Продление на ${formatShiftExtensionDuration(context.settings.durationMinutes)} — " +
                    "${formatCompactMoney(context.settings.priceMinor, context.settings.currency)}. " +
                    "Персонал подтвердит возможность продления."
        }

    private fun guestShiftExtensionPendingText(): String = "Продление работы заведения\n\nОжидает подтверждения"

    private suspend fun notifyStaffChatAboutShiftExtensionRequest(
        venueId: Long,
        orderId: Long,
    ) {
        val notifier = staffChatNotifier ?: return
        val detail =
            try {
                venueOrdersRepository.loadOrderDetail(venueId = venueId, orderId = orderId)
            } catch (e: CancellationException) {
                throw e
            } catch (e: DatabaseUnavailableException) {
                return
            } ?: return
        notifier.notifyBillUpdatedNow(
            StaffBillUpdatedNotification(
                venueId = venueId,
                orderId = orderId,
                displayNumber = detail.displayNumber,
                tableLabel = detail.tableNumber.toString(),
                change = StaffBillUpdateChange.SHIFT_EXTENSION_REQUESTED,
                bill = detail.toOrderBillSnapshot(),
                batches = detail.toStaffOrderBatchLiveBlocks(),
                status = detail.status,
                actionBatchId = staffChatActionBatchId(detail),
                pendingShiftExtension = detail.pendingShiftExtension,
                updatedAt = detail.updatedAt,
            ),
        )
    }

    private fun formatShiftExtensionDuration(durationMinutes: Int): String =
        when (durationMinutes) {
            60 -> "1 час"
            120 -> "2 часа"
            180 -> "3 часа"
            240 -> "4 часа"
            else -> "$durationMinutes мин"
        }

    private data class GuestBotShiftExtensionContext(
        val resolved: ResolvedChatContext,
        val tableSession: TableSessionRecord,
        val tab: GuestTabModel,
        val order: ActiveOrderSummary?,
        val settings: ShiftExtensionSettings,
        val pending: ShiftExtensionRequestRecord?,
    ) {
        val canSubmitRequest: Boolean =
            pending == null &&
                settings.enabled &&
                settings.priceMinor != null &&
                order != null
    }

    private suspend fun showBotMenu(
        chatId: Long,
        reorderMode: Boolean = false,
        sourceMessageId: Long? = null,
    ) {
        logger.warn("SHOW menu")
        val context = resolveGuestContext(chatId) ?: return
        val menu =
            try {
                guestMenuRepository.getMenu(context.table.venueId)
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return
            }
        val categories =
            menu.categories
                .filter { category -> category.items.isNotEmpty() }
                .map { category -> category.id to category.name }
        val includeShiftExtension = shouldShowGuestBotShiftExtensionMenuEntry(context.table.venueId)
        if (categories.isEmpty() && !includeShiftExtension) {
            enqueueMessage(chatId, "В ${context.table.venueName} пока нет категорий меню.")
            return
        }
        upsertBotMenuMessage(
            chatId,
            tableToken = context.table.tableToken,
            if (reorderMode) {
                "Выберите позицию в меню, затем откройте корзину и нажмите «Оформить заказ»."
            } else {
                "${context.table.venueName}\nВыберите категорию."
            },
            TelegramKeyboards.inlineBotMenuCategories(
                categories = categories,
                includeTableActionsBack = reorderMode,
                includeShiftExtension = includeShiftExtension,
            ),
            sourceMessageId = sourceMessageId,
        )
    }

    private suspend fun showFavoriteItemsForCurrentTable(chatId: Long) {
        val contextResult = loadContext(chatId)
        val context =
            when (contextResult) {
                is LoadContextResult.Loaded -> contextResult.context
                LoadContextResult.DatabaseUnavailable -> {
                    enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                    return
                }
                LoadContextResult.Missing -> {
                    enqueueMessage(chatId, "Любимые позиции доступны за столом. Отсканируйте QR-код.")
                    return
                }
            }
        when (ensureGuestTableFlowAccess(context.userId, context.table.venueId)) {
            VenueGuestAccessResult.Allowed -> Unit
            VenueGuestAccessResult.Forbidden -> {
                enqueueMessage(chatId, "Заведение пока не доступно для гостей.")
                runCatching { chatContextRepository.clear(chatId) }
                return
            }
            VenueGuestAccessResult.DatabaseUnavailable -> {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return
            }
        }
        when (checkSubscription(context.table.venueId)) {
            SubscriptionCheckResult.Available -> Unit
            SubscriptionCheckResult.Blocked -> {
                enqueueMessage(chatId, subscriptionBlockedMessage)
                return
            }
            SubscriptionCheckResult.DatabaseUnavailable -> {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return
            }
        }
        val items =
            try {
                guestFavoritesRepository.listFavoriteItemsForVenue(
                    userId = context.userId,
                    venueId = context.table.venueId,
                )
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return
            }
        if (items.isEmpty()) {
            enqueueMessage(
                chatId,
                "У вас пока нет любимых позиций в этом заведении.",
                TelegramKeyboards.inlineTableActionsBack(),
            )
            return
        }
        enqueueMessage(
            chatId,
            "⭐ Любимое\nВыберите позицию.",
            TelegramKeyboards.inlineFavoriteMenuItems(
                items.map { item ->
                    Triple(
                        item.categoryId,
                        item.itemId,
                        "${item.name} — ${formatPrice(item.priceMinor, item.currency)}",
                    )
                },
            ),
        )
    }

    private suspend fun addFavoriteItem(
        chatId: Long,
        from: User,
        callbackQueryId: String,
        data: String,
    ) {
        val itemId = data.removePrefix("fav_i_add:").toLongOrNull()
        if (itemId == null) {
            enqueueCallbackAnswer(chatId, callbackQueryId, text = "Не удалось добавить", showAlert = true)
            return
        }
        val context =
            when (val contextResult = loadContext(chatId)) {
                is LoadContextResult.Loaded -> contextResult.context
                LoadContextResult.DatabaseUnavailable -> {
                    enqueueCallbackAnswer(chatId, callbackQueryId, text = "База недоступна", showAlert = true)
                    return
                }
                LoadContextResult.Missing -> {
                    enqueueCallbackAnswer(
                        chatId,
                        callbackQueryId,
                        text = "Любимые позиции доступны за столом.",
                        showAlert = true,
                    )
                    return
                }
            }
        val item = findCurrentVenueMenuItem(chatId, context.table.venueId, itemId)
        if (item == null) {
            enqueueCallbackAnswer(chatId, callbackQueryId, text = "Эта позиция сейчас недоступна.", showAlert = true)
            return
        }
        val added =
            try {
                guestFavoritesRepository.addItemFavorite(
                    userId = from.id,
                    venueId = context.table.venueId,
                    menuItemId = itemId,
                )
            } catch (e: DatabaseUnavailableException) {
                enqueueCallbackAnswer(chatId, callbackQueryId, text = "База недоступна", showAlert = true)
                return
            }
        if (!added) {
            enqueueCallbackAnswer(chatId, callbackQueryId, text = "Эта позиция сейчас недоступна.", showAlert = true)
            return
        }
        enqueueCallbackAnswer(chatId, callbackQueryId, text = "Добавили позицию в любимые.")
        enqueueMessage(chatId, "Добавили позицию в любимые.")
    }

    private suspend fun removeFavoriteItem(
        chatId: Long,
        from: User,
        callbackQueryId: String,
        data: String,
    ) {
        val itemId = data.removePrefix("fav_i_del:").toLongOrNull()
        if (itemId == null) {
            enqueueCallbackAnswer(chatId, callbackQueryId, text = "Не удалось убрать", showAlert = true)
            return
        }
        try {
            guestFavoritesRepository.removeItemFavorite(from.id, itemId)
        } catch (e: DatabaseUnavailableException) {
            enqueueCallbackAnswer(chatId, callbackQueryId, text = "База недоступна", showAlert = true)
            return
        }
        enqueueCallbackAnswer(chatId, callbackQueryId, text = "Убрали позицию из любимых.")
        enqueueMessage(chatId, "Убрали позицию из любимых.")
    }

    private suspend fun findCurrentVenueMenuItem(
        chatId: Long,
        venueId: Long,
        itemId: Long,
    ): FavoriteMenuItem? {
        val menu =
            try {
                guestMenuRepository.getMenu(venueId)
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return null
            }
        menu.categories.forEach { category ->
            val item = category.items.firstOrNull { it.id == itemId }
            if (item != null) {
                return FavoriteMenuItem(
                    itemId = item.id,
                    venueId = venueId,
                    categoryId = category.id,
                    name = item.name,
                    priceMinor = item.priceMinor,
                    currency = item.currency,
                )
            }
        }
        return null
    }

    private suspend fun showBotSplitBillEntry(chatId: Long) {
        val context = resolveGuestContext(chatId) ?: return
        val currentTab = resolveCurrentBotTab(chatId, context) ?: return
        val currentTabType = currentTab.type.uppercase(Locale.ROOT)
        if (currentTabType == "SHARED") {
            val sharedInfoText =
                if (currentTab.ownerUserId == context.userId) {
                    val inviteCode = createSharedInviteCode(chatId, context, currentTab.tableSessionId, currentTab.id)
                    if (inviteCode != null) {
                        "Текущий счёт: Общий.\nКод приглашения: $inviteCode"
                    } else {
                        "Текущий счёт: Общий.\nВы создатель общего счёта."
                    }
                } else {
                    "Текущий счёт: Общий.\nВы уже присоединились к общему счёту."
                }
            enqueueMessage(chatId, sharedInfoText)
            return
        }
        enqueueMessage(
            chatId,
            "Общий счёт\nВыберите действие.",
            TelegramKeyboards.inlineBotSplitBillEntryActions(),
        )
    }

    private suspend fun showBotMenuCategoryItems(
        chatId: Long,
        data: String,
        sourceMessageId: Long? = null,
    ) {
        logger.warn(
            "SHOW category_items data={}",
            sanitizeTelegramForLog(data),
        )
        val parsed = parseBotMenuCategoryData(data)
        logger.warn(
            "SHOW category_items data={} parsed={}",
            sanitizeTelegramForLog(data),
            parsed?.let { "${it.first}:${it.second}" } ?: "null",
        )
        if (parsed == null) {
            logger.warn(
                "Invalid menu category callback data chat_id={} message_id={} data={}",
                chatId,
                sourceMessageId,
                sanitizeTelegramForLog(data),
            )
            enqueueMessage(chatId, "Не удалось открыть категорию. Попробуйте ещё раз.")
            return
        }
        val (categoryId, requestedPage) = parsed
        val context = resolveGuestContext(chatId) ?: return
        val menu =
            try {
                guestMenuRepository.getMenu(context.table.venueId)
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return
            }
        val category =
            menu.categories.firstOrNull { it.id == categoryId } ?: run {
                enqueueMessage(chatId, "Категория не найдена.")
                return
            }
        val lines =
            category.items.mapIndexed { index, item ->
                "${index + 1}. ${item.name} — ${formatPrice(item.priceMinor, item.currency)}"
            }
        if (lines.isEmpty()) {
            enqueueMessage(chatId, "В категории \"${category.name}\" пока нет доступных позиций.")
            return
        }
        val totalPages = ((category.items.size - 1) / botMenuItemsPerPage) + 1
        val page = requestedPage.coerceIn(0, totalPages - 1)
        val fromIndex = page * botMenuItemsPerPage
        val toIndex = minOf(fromIndex + botMenuItemsPerPage, category.items.size)
        val pageItems = category.items.subList(fromIndex, toIndex)
        upsertBotMenuMessage(
            chatId,
            tableToken = context.table.tableToken,
            buildString {
                append(category.name)
                append("\n")
                append("Выберите позицию.")
                if (totalPages > 1) {
                    append("\n")
                    append("Страница ${page + 1}/$totalPages")
                }
            },
            TelegramKeyboards.inlineBotMenuItems(
                categoryId = category.id,
                items =
                    pageItems.map { item ->
                        item.id to "${item.name} — ${formatPrice(item.priceMinor, item.currency)}"
                    },
                page = page,
                totalPages = totalPages,
            ),
            sourceMessageId = sourceMessageId,
        )
    }

