    private suspend fun reorderBotMenuItem(
        chatId: Long,
        data: String,
        callbackId: String,
    ) {
        val (categoryId, itemId) = parseBotMenuItemData(data) ?: return
        val context = resolveGuestContext(chatId) ?: return
        val currentTab = resolveCurrentBotTab(chatId, context) ?: return
        val menu =
            try {
                guestMenuRepository.getMenu(context.table.venueId)
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return
            }
        val category =
            menu.categories.firstOrNull { it.id == categoryId } ?: run {
                enqueueMessage(chatId, "Категория не найдена.")
                return
            }
        val item =
            category.items.firstOrNull { it.id == itemId } ?: run {
                enqueueMessage(chatId, "Позиция не найдена.")
                return
            }
        val activeOrder =
            ordersRepository.findActiveOrderSummaryForTab(
                tableSessionId = currentTab.tableSessionId,
                tabId = currentTab.id,
            )
        if (activeOrder == null) {
            if (
                !addItemToBotDraftCart(
                    chatId = chatId,
                    tableToken = context.table.tableToken,
                    tableSessionId = currentTab.tableSessionId,
                    tabId = currentTab.id,
                    item = item,
                )
            ) {
                warnBotDraftCartScopeMismatch(chatId)
                return
            }
            enqueueMessage(
                chatId,
                buildString {
                    append(item.name)
                    append("\n")
                    append("Цена: ${formatPrice(item.priceMinor, item.currency)}")
                    append("\n\n")
                    append("Активного заказа нет. Позиция добавлена в корзину.")
                },
                TelegramKeyboards.inlineBotMenuPostAddActions(category.id),
            )
            return
        }
        val createdBatch =
            createGuestBatchFromBotItems(
                chatId = chatId,
                context = context,
                idempotencyKey = "bot-reorder:$callbackId",
                tableSessionId = currentTab.tableSessionId,
                tabId = currentTab.id,
                items =
                    listOf(
                        OrderBatchItemInput(
                            itemId = item.id,
                            qty = 1,
                        ),
                    ),
            ) ?: return
        enqueueMessage(
            chatId,
            buildString {
                append(item.name)
                append("\n")
                append("Цена: ${formatPrice(item.priceMinor, item.currency)}")
                append("\n\n")
                append(
                    "✅ Дозаказ отправлен в активный ${
                        formatTelegramOrderDisplayLabel(
                            createdBatch.orderId,
                            createdBatch.displayNumber,
                            createdBatch.displayDate,
                        )
                    }.",
                )
            },
            TelegramKeyboards.inlineBotMenuPostAddActions(category.id),
        )
    }

    private suspend fun showBotMenuCart(
        chatId: Long,
        sourceMessageId: Long? = null,
    ) {
        val context = resolveGuestContext(chatId) ?: return
        val currentTab = resolveCurrentBotTab(chatId, context) ?: return
        val showSplitBillActions = currentTab.type == "PERSONAL"
        val key = BotDraftCartKey(chatId = chatId, tableToken = context.table.tableToken)
        clearBotTransientScreens(chatId, key)
        val items = getBotDraftCartItems(chatId, context.table.tableToken)
        val guestComment = botDraftCartComments[key]?.trim()?.takeIf { it.isNotBlank() }
        if (items.isNotEmpty() && isBotDraftCartScopeMismatch(key, currentTab)) {
            sendBotCartScreenMessage(
                chatId,
                key,
                "Корзина собрана для другого счёта. Очистите её и соберите заново для текущего счёта.",
                TelegramKeyboards.inlineBotMenuCartSummaryActions(
                    showSplitBillActions = false,
                    hasComment = guestComment != null,
                ),
            )
            return
        }
        if (items.isEmpty()) {
            sendBotCartScreenMessage(
                chatId,
                key,
                "Корзина пуста.",
                TelegramKeyboards.inlineBotMenuCartSummaryActions(
                    showSplitBillActions = showSplitBillActions,
                    hasComment = guestComment != null,
                ),
            )
            return
        }
        val totalsByCurrency =
            items
                .groupBy { it.currency.uppercase(Locale.ROOT) }
                .mapValues { entry ->
                    entry.value.sumOf { it.priceMinor * it.qty.toLong() }
                }
        val promotionPreview = buildBotCartPromotionPreview(context.table.venueId, context.userId, items, key)
        val loyaltyProgressText =
            buildBotCartLoyaltyProgressText(
                venueId = context.table.venueId,
                userId = context.userId,
                redemptionPreview = promotionPreview?.loyaltyRedemption,
            )
        val totalText =
            buildBotCartTotalText(
                totalsByCurrency = totalsByCurrency,
                promotionPreview = promotionPreview,
            )
        items.forEach { item ->
            val lineTotal = formatPrice(item.priceMinor * item.qty.toLong(), item.currency)
            sendBotCartScreenMessage(
                chatId,
                key,
                buildString {
                    append("${item.name}\n")
                    append("Количество: ${item.qty}\n")
                    append("Сумма: $lineTotal")
                },
                TelegramKeyboards.inlineBotMenuCartItemActions(item.lineId),
            )
        }
        sendBotCartScreenMessage(
            chatId,
            key,
            buildString {
                append("🧺 Корзина\n")
                if (promotionPreview != null) {
                    append(
                        items.joinToString("\n") { item ->
                            val lineTotal = item.priceMinor * item.qty.toLong()
                            "• ${item.name} ×${item.qty} — ${formatCompactMoney(lineTotal, item.currency)}"
                        },
                    )
                    append("\n")
                    append(promotionPreview.text)
                    append("\n")
                }
                loyaltyProgressText?.let {
                    append(it)
                    append("\n")
                }
                append(totalText)
                append("\nКомментарий: ${guestComment ?: "—"}")
            },
            TelegramKeyboards.inlineBotMenuCartSummaryActions(
                showSplitBillActions = showSplitBillActions,
                hasComment = guestComment != null,
                hasGiftChoice = promotionPreview?.giftChoices?.isNotEmpty() == true,
            ),
        )
    }

    private fun buildBotCartTotalText(
        totalsByCurrency: Map<String, Long>,
        promotionPreview: BotCartPromotionPreview?,
    ): String =
        if (promotionPreview == null) {
            if (totalsByCurrency.size == 1) {
                val (currency, totalMinor) = totalsByCurrency.entries.first()
                "Итого: ${formatPrice(totalMinor, currency)}"
            } else {
                buildString {
                    append("Итого:\n")
                    append(
                        totalsByCurrency.entries.joinToString("\n") { (currency, totalMinor) ->
                            "- ${formatPrice(totalMinor, currency)}"
                        },
                    )
                }
            }
        } else if (totalsByCurrency.size == 1) {
            val (currency, totalMinor) = totalsByCurrency.entries.first()
            val discountMinor = promotionPreview.discountsByCurrency[currency.uppercase(Locale.ROOT)] ?: 0L
            val label =
                if (promotionPreview.loyaltyRedemption != null) {
                    "Итого к оплате"
                } else {
                    "Итого к оплате после акции"
                }
            val payableTotalMinor = (totalMinor - discountMinor).coerceAtLeast(0L)
            "$label: ${formatCompactMoney(payableTotalMinor, currency)}"
        } else {
            buildString {
                append(
                    if (promotionPreview.loyaltyRedemption != null) {
                        "Итого к оплате:\n"
                    } else {
                        "Итого к оплате после акции:\n"
                    },
                )
                append(
                    totalsByCurrency.entries.joinToString("\n") { (currency, totalMinor) ->
                        val discountMinor =
                            promotionPreview.discountsByCurrency[currency.uppercase(Locale.ROOT)]
                                ?: 0L
                        "- ${formatCompactMoney((totalMinor - discountMinor).coerceAtLeast(0L), currency)}"
                    },
                )
            }
        }

    private suspend fun buildBotCartLoyaltyProgressText(
        venueId: Long,
        userId: Long,
        redemptionPreview: LoyaltyRedemptionPreview?,
    ): String? {
        if (redemptionPreview != null) return null
        val progress =
            try {
                loyaltyRepository.getGuestProgress(venueId, userId)
            } catch (e: DatabaseUnavailableException) {
                return null
            } ?: return null
        if (progress.progressCount <= 0 && progress.rewardsAvailable <= 0) {
            return null
        }
        val baseText =
            if (progress.rewardsAvailable > 0) {
                if (progress.rewardsAvailable == 1) {
                    "🎁 Лояльность: у вас есть бесплатный кальян."
                } else {
                    "🎁 Лояльность: доступно бесплатных кальянов: ${progress.rewardsAvailable}."
                }
            } else {
                "🎁 Лояльность: ${progress.progressCount}/${loyaltyPaidRequired(
                    progress.nthValue,
                )} до бесплатного кальяна."
            }
        return baseText
    }

    private suspend fun buildBotCartPromotionPreview(
        venueId: Long,
        userId: Long,
        items: List<BotDraftCartItem>,
        key: BotDraftCartKey,
    ): BotCartPromotionPreview? {
        if (items.isEmpty()) return null
        val loyaltyPreview = buildBotCartLoyaltyRedemptionPreview(venueId, userId, items)
        val now = Instant.now()
        val rules =
            try {
                venuePromotionRuleRepository.listActiveRulesForVenueAt(venueId, now)
            } catch (e: DatabaseUnavailableException) {
                return formatBotCartPromotionPreview(PromotionRulePreviewResult(emptyList()), loyaltyPreview)
            }
        if (rules.isEmpty()) {
            return formatBotCartPromotionPreview(
                PromotionRulePreviewResult(emptyList()),
                loyaltyPreview,
            )
        }
        val menu =
            try {
                guestMenuRepository.getMenu(venueId)
            } catch (e: DatabaseUnavailableException) {
                return formatBotCartPromotionPreview(PromotionRulePreviewResult(emptyList()), loyaltyPreview)
            }
        val effectiveTypesByItemId =
            menu.categories
                .flatMap { category ->
                    category.items.map { item -> item.id to (item.itemType ?: category.categoryType) }
                }
                .toMap()
        val cartItems =
            items.mapNotNull { item ->
                if (
                    loyaltyPreview != null &&
                    (
                        loyaltyPreview.lineId == item.lineId ||
                            (loyaltyPreview.lineId == null && loyaltyPreview.menuItemId == item.itemId)
                    )
                ) {
                    return@mapNotNull null
                }
                val effectiveType = effectiveTypesByItemId[item.itemId] ?: return@mapNotNull null
                PromotionRuleCartItem(
                    lineId = item.lineId,
                    menuItemId = item.itemId,
                    itemName = item.name,
                    qty = item.qty,
                    priceMinor = item.priceMinor,
                    currency = item.currency,
                    effectiveType = effectiveType,
                )
            }
        if (cartItems.isEmpty()) {
            return formatBotCartPromotionPreview(
                PromotionRulePreviewResult(emptyList()),
                loyaltyPreview,
            )
        }
        val preview =
            PromotionRuleEngine.preview(
                venueId = venueId,
                now = now,
                venueZoneId = resolveVenueZoneId(venueId),
                cartItems = cartItems,
                activeRules = rules,
                selectedGiftChoices = botGiftChoices[key].orEmpty(),
                skippedGiftRuleIds = botSkippedGiftRules[key].orEmpty(),
            )
        return formatBotCartPromotionPreview(preview, loyaltyPreview)
    }

    private suspend fun buildBotCartLoyaltyRedemptionPreview(
        venueId: Long,
        userId: Long,
        items: List<BotDraftCartItem>,
    ): LoyaltyRedemptionPreview? =
        try {
            loyaltyRepository.previewRedemptionForCart(
                venueId = venueId,
                userId = userId,
                items =
                    items.map {
                        LoyaltyCartItem(
                            lineId = it.lineId,
                            menuItemId = it.itemId,
                            itemName = it.name,
                            qty = it.qty,
                            priceMinor = it.priceMinor,
                            currency = it.currency,
                        )
                    },
            )
        } catch (e: DatabaseUnavailableException) {
            null
        }

    private fun formatBotCartPromotionPreview(
        preview: PromotionRulePreviewResult,
        loyaltyPreview: LoyaltyRedemptionPreview?,
    ): BotCartPromotionPreview? {
        if (
            preview.adjustments.isEmpty() &&
            preview.gifts.isEmpty() &&
            preview.giftChoices.isEmpty() &&
            loyaltyPreview == null
        ) {
            return null
        }
        val discountsByCurrency =
            buildMap {
                preview.adjustments
                    .groupBy { it.currency.uppercase(Locale.ROOT) }
                    .forEach { (currency, adjustments) ->
                        put(currency, adjustments.sumOf { it.discountMinor })
                    }
                loyaltyPreview?.let { loyalty ->
                    val currency = loyalty.currency.uppercase(Locale.ROOT)
                    put(currency, (this[currency] ?: 0L) + loyalty.discountMinor)
                }
            }
        val discountLines =
            preview.adjustments
                .groupBy { it.label to it.currency }
                .map { (key, adjustments) ->
                    val (label, currency) = key
                    val discountMinor = adjustments.sumOf { it.discountMinor }
                    "🎁 $label: −${formatCompactMoney(discountMinor, currency)}"
                }
        val loyaltyLines =
            loyaltyPreview?.let { loyalty ->
                listOf(
                    "🎁 Лояльность: бесплатный кальян −" +
                        formatCompactMoney(loyalty.discountMinor, loyalty.currency),
                )
            } ?: emptyList()
        val giftLines =
            preview.gifts.map { gift ->
                "🎁 ${gift.rewardItemName} в подарок к «${gift.triggerItemName}»"
            }
        val giftChoiceLines =
            preview.giftChoices.map {
                "🎁 Доступен подарок: выберите один вариант."
            }
        val lines =
            buildList {
                addAll(discountLines)
                addAll(loyaltyLines)
                addAll(giftLines)
                addAll(giftChoiceLines)
                if (giftLines.isNotEmpty()) {
                    add("Подарок будет добавлен при оформлении, если акция ещё активна.")
                }
            }
        return BotCartPromotionPreview(
            text = lines.joinToString("\n"),
            discountsByCurrency = discountsByCurrency,
            giftChoices = preview.giftChoices,
            loyaltyRedemption = loyaltyPreview,
        )
    }

    private suspend fun showBotGiftChoice(chatId: Long) {
        val context = resolveGuestContext(chatId) ?: return
        val currentTab = resolveCurrentBotTab(chatId, context) ?: return
        val key = BotDraftCartKey(chatId = chatId, tableToken = context.table.tableToken)
        val items = getBotDraftCartItems(chatId, context.table.tableToken)
        if (items.isEmpty()) {
            showBotMenuCart(chatId)
            return
        }
        if (isBotDraftCartScopeMismatch(key, currentTab)) {
            warnBotDraftCartScopeMismatch(chatId)
            return
        }
        val choice =
            buildBotCartPromotionPreview(
                context.table.venueId,
                context.userId,
                items,
                key,
            )?.giftChoices?.firstOrNull()
        if (choice == null) {
            enqueueMessage(chatId, "Сейчас нет подарка для выбора.")
            showBotMenuCart(chatId)
            return
        }
        val selected = botGiftChoices[key]?.get(choice.ruleId)
        enqueueMessage(
            chatId,
            buildString {
                append("🎁 Вам доступен подарок.\n\n")
                append("Выберите один вариант к позиции «")
                append(choice.triggerItemName)
                append("».")
            },
            TelegramKeyboards.inlineBotGiftChoiceOptionsActions(
                choice.options.map { option ->
                    Triple(option.menuItemId, option.menuItemName, option.menuItemId == selected)
                },
            ),
        )
    }

    private suspend fun selectBotGiftChoice(
        chatId: Long,
        data: String,
    ) {
        val rewardMenuItemId =
            data.removePrefix("bot_gift_opt:").toLongOrNull() ?: run {
                enqueueMessage(chatId, "Не удалось выбрать подарок. Попробуйте ещё раз.")
                return
            }
        val context = resolveGuestContext(chatId) ?: return
        val currentTab = resolveCurrentBotTab(chatId, context) ?: return
        val key = BotDraftCartKey(chatId = chatId, tableToken = context.table.tableToken)
        val items = getBotDraftCartItems(chatId, context.table.tableToken)
        if (items.isEmpty()) {
            showBotMenuCart(chatId)
            return
        }
        if (isBotDraftCartScopeMismatch(key, currentTab)) {
            warnBotDraftCartScopeMismatch(chatId)
            return
        }
        val choice =
            buildBotCartPromotionPreview(
                context.table.venueId,
                context.userId,
                items,
                key,
            )?.giftChoices?.firstOrNull()
        if (choice == null) {
            enqueueMessage(chatId, "Сейчас нет подарка для выбора.")
            showBotMenuCart(chatId)
            return
        }
        val selectedOption =
            choice.options.firstOrNull { it.menuItemId == rewardMenuItemId } ?: run {
                enqueueMessage(chatId, "Этот подарок сейчас недоступен. Выберите другой вариант.")
                showBotGiftChoice(chatId)
                return
            }
        botGiftChoices.computeIfAbsent(key) { ConcurrentHashMap() }[choice.ruleId] = selectedOption.menuItemId
        botSkippedGiftRules[key]?.remove(choice.ruleId)
        enqueueMessage(chatId, "Подарок выбран: ${selectedOption.menuItemName}.")
        showBotMenuCart(chatId)
    }

    private suspend fun clearBotMenuCart(
        chatId: Long,
        sourceMessageId: Long? = null,
    ) {
        val context = resolveGuestContext(chatId) ?: return
        clearBotDraftCart(chatId, context.table.tableToken)
        showBotMenuCart(chatId)
    }

    private suspend fun changeBotMenuCartItemQty(
        chatId: Long,
        data: String,
        delta: Int,
        sourceMessageId: Long? = null,
    ) {
        val itemId = parseBotMenuCartItemId(data) ?: return
        val context = resolveGuestContext(chatId) ?: return
        val key = BotDraftCartKey(chatId = chatId, tableToken = context.table.tableToken)
        val cart =
            botDraftCarts[key] ?: run {
                showBotMenuCart(chatId)
                return
            }
        cart.compute(itemId) { _, existing ->
            val current = existing ?: return@compute null
            val nextQty = current.qty + delta
            if (nextQty <= 0) null else current.copy(qty = nextQty)
        }
        if (cart.isEmpty()) {
            botDraftCarts.remove(key)
        }
        botSkippedGiftRules.remove(key)
        showBotMenuCart(chatId)
    }

    private suspend fun removeBotMenuCartItem(
        chatId: Long,
        data: String,
        sourceMessageId: Long? = null,
    ) {
        val itemId = parseBotMenuCartItemId(data) ?: return
        val context = resolveGuestContext(chatId) ?: return
        val key = BotDraftCartKey(chatId = chatId, tableToken = context.table.tableToken)
        val cart =
            botDraftCarts[key] ?: run {
                showBotMenuCart(chatId)
                return
            }
        cart.remove(itemId)
        if (cart.isEmpty()) {
            botDraftCarts.remove(key)
        }
        botSkippedGiftRules.remove(key)
        showBotMenuCart(chatId)
    }

    private suspend fun checkoutBotMenuCart(
        chatId: Long,
        callbackId: String,
        skipPendingGiftChoice: Boolean = false,
    ) {
        val context = resolveGuestContext(chatId) ?: return
        val currentTab = resolveCurrentBotTab(chatId, context) ?: return
        val draftItems = getBotDraftCartItems(chatId, context.table.tableToken)
        if (draftItems.isEmpty()) {
            showBotMenuCart(chatId)
            return
        }
        val key = BotDraftCartKey(chatId = chatId, tableToken = context.table.tableToken)
        if (isBotDraftCartScopeMismatch(key, currentTab)) {
            warnBotDraftCartScopeMismatch(chatId)
            return
        }
        val promotionPreview = buildBotCartPromotionPreview(context.table.venueId, context.userId, draftItems, key)
        val pendingGiftChoice = promotionPreview?.giftChoices?.firstOrNull()
        if (pendingGiftChoice != null && !skipPendingGiftChoice) {
            val selectedGift = botGiftChoices[key]?.get(pendingGiftChoice.ruleId)
            enqueueMessage(
                chatId,
                if (selectedGift == null) {
                    "Вы ещё не выбрали подарок по акции."
                } else {
                    "Выбранный подарок сейчас недоступен. Выберите другой подарок или оформите заказ без подарка."
                },
                TelegramKeyboards.inlineBotGiftChoiceRequiredActions(),
            )
            return
        }
        if (skipPendingGiftChoice && pendingGiftChoice != null) {
            botSkippedGiftRules.computeIfAbsent(key) { ConcurrentHashMap.newKeySet() }.add(pendingGiftChoice.ruleId)
        }
        val cartComment = botDraftCartComments[key]
        val createdBatch =
            createGuestBatchFromBotItems(
                chatId = chatId,
                context = context,
                idempotencyKey = "bot-cart-checkout:$callbackId",
                tableSessionId = currentTab.tableSessionId,
                tabId = currentTab.id,
                comment = buildBotDraftCartSubmitComment(draftItems, cartComment),
                items =
                    draftItems.map { item ->
                        OrderBatchItemInput(
                            itemId = item.itemId,
                            qty = item.qty,
                            selectedOptionId = item.optionId,
                        )
                    },
                selectedGiftChoices = botGiftChoices[key].orEmpty(),
                skippedGiftRuleIds = botSkippedGiftRules[key].orEmpty(),
            )
                ?: return
        clearBotCartScreenMessages(chatId, key)
        clearBotDraftCart(chatId, context.table.tableToken)
        enqueueMessage(
            chatId,
            "✅ Заказ отправлен.\n${formatTelegramOrderDisplayLabel(
                createdBatch.orderId,
                createdBatch.displayNumber,
                createdBatch.displayDate,
            )}.\nЧто дальше?",
            TelegramKeyboards.inlineBotReorderAction(),
        )
    }

    private suspend fun promptBotMenuCartComment(chatId: Long) {
        val context = resolveGuestContext(chatId) ?: return
        val key = BotDraftCartKey(chatId = chatId, tableToken = context.table.tableToken)
        dialogStateRepository.set(
            chatId,
            DialogState(DialogStateType.BOT_MENU_CART_WAIT_COMMENT),
        )
        val existing = botDraftCartComments[key]?.trim()?.takeIf { it.isNotBlank() }
        enqueueMessage(
            chatId,
            buildString {
                append("Введите комментарий к заказу или дозаказу.\n")
                append("Отправьте «—», чтобы удалить комментарий.")
                existing?.let {
                    append("\n\nТекущий комментарий: $it")
                }
            },
        )
    }

    private suspend fun proceedBotMenuCartComment(
        chatId: Long,
        rawText: String,
    ) {
        val context =
            resolveGuestContext(chatId) ?: run {
                dialogStateRepository.clear(chatId)
                return
            }
        val key = BotDraftCartKey(chatId = chatId, tableToken = context.table.tableToken)
        val trimmed = rawText.trim()
        if (trimmed == "-" || trimmed == "—") {
            botDraftCartComments.remove(key)
            dialogStateRepository.clear(chatId)
            enqueueMessage(chatId, "✅ Комментарий удалён.")
            showBotMenuCart(chatId)
            return
        }
        if (trimmed.isBlank()) {
            enqueueMessage(chatId, "Комментарий пустой. Введите текст или отправьте «—».")
            return
        }
        if (trimmed.length > 500) {
            enqueueMessage(chatId, "Комментарий слишком длинный. До 500 символов.")
            return
        }
        botDraftCartComments[key] = trimmed
        dialogStateRepository.clear(chatId)
        enqueueMessage(chatId, "✅ Комментарий сохранён.")
        showBotMenuCart(chatId)
    }

    private suspend fun promptBotJoinShared(chatId: Long) {
        resolveGuestContext(chatId) ?: return
        dialogStateRepository.set(chatId, DialogState(DialogStateType.BOT_JOIN_SHARED_WAIT_CODE))
        botJoinSharedAwaitingChats.add(chatId)
        enqueueMessage(chatId, "Введите 4-значный код общего счёта.")
    }

    private suspend fun proceedBotJoinSharedCode(
        chatId: Long,
        rawCode: String,
    ) {
        val context = resolveGuestContext(chatId) ?: return
        val code = rawCode.trim()
        if (!code.matches(Regex("^\\d{4}$"))) {
            enqueueMessage(chatId, "Нужен 4-значный код. Попробуйте ещё раз.")
            return
        }
        val tableSession = resolveCurrentTableSession(chatId, context) ?: return
        val joinedTab =
            try {
                guestTabsRepository.joinByInvite(
                    venueId = context.table.venueId,
                    tableSessionId = tableSession.id,
                    userId = context.userId,
                    token = code,
                )
            } catch (e: CancellationException) {
                throw e
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return
            }
        if (joinedTab == null) {
            enqueueMessage(chatId, "Код недействителен или истёк. Попробуйте ещё раз.")
            return
        }
        val key = BotDraftCartKey(chatId = chatId, tableToken = context.table.tableToken)
        clearBotDraftCartIfScopedToDifferentTab(
            chatId = chatId,
            tableToken = context.table.tableToken,
            targetScope =
                BotDraftCartScope(
                    tableSessionId = joinedTab.tableSessionId,
                    tabId = joinedTab.id,
                ),
        )
        botSelectedTabIds[key] = joinedTab.id
        botJoinSharedAwaitingChats.remove(chatId)
        dialogStateRepository.clear(chatId)
        enqueueMessage(
            chatId,
            "✅ Вы присоединились к общему счёту.",
        )
    }

    private suspend fun createBotSharedTab(chatId: Long) {
        val context = resolveGuestContext(chatId) ?: return
        val tableSession = resolveCurrentTableSession(chatId, context) ?: return
        val sharedTab =
            try {
                guestTabsRepository.createSharedTab(
                    venueId = context.table.venueId,
                    tableSessionId = tableSession.id,
                    ownerUserId = context.userId,
                )
            } catch (e: CancellationException) {
                throw e
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return
            }
        val key = BotDraftCartKey(chatId = chatId, tableToken = context.table.tableToken)
        clearBotDraftCartIfScopedToDifferentTab(
            chatId = chatId,
            tableToken = context.table.tableToken,
            targetScope =
                BotDraftCartScope(
                    tableSessionId = sharedTab.tableSessionId,
                    tabId = sharedTab.id,
                ),
        )
        botSelectedTabIds[key] = sharedTab.id
        val inviteCode = createSharedInviteCode(chatId, context, tableSession.id, sharedTab.id)
        if (inviteCode == null) {
            enqueueMessage(chatId, "Общий счёт создан, но код пока не сгенерирован. Попробуйте ещё раз.")
            return
        }
        enqueueMessage(
            chatId,
            "✅ Общий счёт создан.\nКод приглашения: $inviteCode",
        )
    }

    private suspend fun createSharedInviteCode(
        chatId: Long,
        context: ResolvedChatContext,
        tableSessionId: Long,
        tabId: Long,
    ): String? {
        try {
            guestTabsRepository.deleteExpiredInvites()
        } catch (e: CancellationException) {
            throw e
        } catch (e: DatabaseUnavailableException) {
            enqueueMessage(chatId, "База недоступна, попробуйте позже.")
            return null
        }
        val expiresAt = Instant.now().plus(inviteCodeTtl)
        repeat(inviteCodeMaxAttempts) {
            val code = inviteCodeRandom.nextInt(inviteCodeRangeExclusive).toString().padStart(inviteCodeLength, '0')
            val createResult =
                try {
                    guestTabsRepository.createInvite(
                        tabId = tabId,
                        venueId = context.table.venueId,
                        tableSessionId = tableSessionId,
                        createdBy = context.userId,
                        token = code,
                        expiresAt = expiresAt,
                    )
                } catch (e: CancellationException) {
                    throw e
                } catch (e: DatabaseUnavailableException) {
                    enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                    return null
                }
            when (createResult) {
                CreateInviteResult.CREATED -> return code
                CreateInviteResult.TOKEN_CONFLICT -> Unit
                CreateInviteResult.FORBIDDEN -> return null
            }
        }
        return null
    }

    private suspend fun resolveCurrentTableSession(
        chatId: Long,
        context: ResolvedChatContext,
    ) = try {
        tableSessionRepository.resolveActiveSession(
            venueId = context.table.venueId,
            tableId = context.table.tableId,
            ttl = tableSessionTtl,
        )
    } catch (e: CancellationException) {
        throw e
    } catch (e: DatabaseUnavailableException) {
        enqueueMessage(chatId, "База недоступна, попробуйте позже.")
        null
    }

    private suspend fun createGuestBatchFromBotItems(
        chatId: Long,
        context: ResolvedChatContext,
        idempotencyKey: String,
        tableSessionId: Long? = null,
        tabId: Long? = null,
        comment: String? = null,
        items: List<OrderBatchItemInput>,
        selectedGiftChoices: Map<Long, Long> = emptyMap(),
        skippedGiftRuleIds: Set<Long> = emptySet(),
    ): com.hookah.platform.backend.telegram.db.CreatedOrderBatch? {
        val tableSession =
            try {
                if (tableSessionId != null) {
                    tableSessionRepository.touchActiveSession(
                        tableSessionId = tableSessionId,
                        venueId = context.table.venueId,
                        tableId = context.table.tableId,
                        ttl = tableSessionTtl,
                    )
                } else {
                    tableSessionRepository.resolveActiveSession(
                        venueId = context.table.venueId,
                        tableId = context.table.tableId,
                        ttl = tableSessionTtl,
                    )
                }
            } catch (e: CancellationException) {
                throw e
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return null
            } ?: run {
                enqueueMessage(chatId, "Сессия стола истекла. Отсканируйте QR ещё раз.")
                return null
            }
        val checkedRequestedTabId =
            if (tabId != null) {
                val isMember =
                    try {
                        guestTabsRepository.isTabMember(
                            tabId = tabId,
                            venueId = context.table.venueId,
                            tableSessionId = tableSession.id,
                            userId = context.userId,
                        )
                    } catch (e: CancellationException) {
                        throw e
                    } catch (e: DatabaseUnavailableException) {
                        enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                        return null
                    }
                tabId.takeIf { isMember }
            } else {
                null
            }
        val effectiveTabId =
            if (checkedRequestedTabId != null) {
                checkedRequestedTabId
            } else {
                val personalTab =
                    try {
                        guestTabsRepository.ensurePersonalTab(
                            venueId = context.table.venueId,
                            tableSessionId = tableSession.id,
                            userId = context.userId,
                        )
                    } catch (e: CancellationException) {
                        throw e
                    } catch (e: DatabaseUnavailableException) {
                        enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                        return null
                    }
                personalTab.id
            }
        return try {
            val createdBatch =
                ordersRepository.createGuestOrderBatch(
                    tableId = context.table.tableId,
                    venueId = context.table.venueId,
                    tableSessionId = tableSession.id,
                    userId = context.userId,
                    idempotencyKey = idempotencyKey,
                    tabId = effectiveTabId,
                    comment = comment,
                    items = items,
                    venueZoneId = resolveVenueZoneId(context.table.venueId),
                    selectedGiftChoices = selectedGiftChoices,
                    skippedGiftRuleIds = skippedGiftRuleIds,
                )
            if (createdBatch == null) {
                enqueueMessage(chatId, "Не удалось оформить заказ, попробуйте ещё раз.")
                null
            } else {
                notifyStaffChatAboutOrderBatch(
                    context = context,
                    createdBatch = createdBatch,
                    comment = comment,
                    items = items,
                )
                createdBatch
            }
        } catch (e: CancellationException) {
            throw e
        } catch (e: InvalidInputException) {
            enqueueMessage(
                chatId,
                "Позиция или выбранный вкус сейчас недоступны. Обновите меню и соберите корзину заново.",
            )
            null
        } catch (e: DatabaseUnavailableException) {
            enqueueMessage(chatId, "База недоступна, попробуйте позже.")
            null
        }
    }

    private suspend fun notifyStaffChatAboutOrderBatch(
        context: ResolvedChatContext,
        createdBatch: CreatedOrderBatch,
        comment: String?,
        items: List<OrderBatchItemInput>,
    ) {
        if (createdBatch.idempotencyReplay) {
            return
        }
        val notifier = staffChatNotifier ?: return
        val summary = staffChatCreatedBatchItemsSummary(createdBatch, items, context.table.venueId)
        val totalCurrency = createdBatch.items.firstOrNull()?.currency
        val totalPayableMinor =
            createdBatch.items
                .takeIf { it.isNotEmpty() }
                ?.sumOf { item -> item.priceMinor * item.qty }
                ?.let { gross -> gross - createdBatch.promotionDiscounts.sumOf { it.discountMinor } }
                ?.coerceAtLeast(0L)
        val isReplacementBeforeAccept =
            resolveReplacementBeforeAcceptBatchFlag(
                venueId = context.table.venueId,
                orderId = createdBatch.orderId,
                batchId = createdBatch.batchId,
            )
        notifier.notifyNewBatchNow(
            NewBatchNotification(
                venueId = context.table.venueId,
                orderId = createdBatch.orderId,
                batchId = createdBatch.batchId,
                tableLabel = context.table.tableNumber.toString(),
                itemsSummary = summary,
                comment = comment,
                displayNumber = createdBatch.displayNumber,
                isFirstBatch = createdBatch.isFirstBatch,
                isReplacementBeforeAccept = isReplacementBeforeAccept,
                guestDisplayName = loadGuestDisplayName(context.userId),
                promotionDiscounts =
                    createdBatch.promotionDiscounts.map { discount ->
                        NewBatchPromotionDiscount(
                            label = discount.label,
                            discountMinor = discount.discountMinor,
                            currency = discount.currency,
                            ruleType = discount.ruleType,
                        )
                    },
                totalPayableMinor = totalPayableMinor,
                totalCurrency = totalCurrency,
            ),
        )
    }

    private suspend fun staffChatCreatedBatchItemsSummary(
        createdBatch: CreatedOrderBatch,
        fallbackItems: List<OrderBatchItemInput>,
        venueId: Long,
    ): String {
        if (createdBatch.items.isNotEmpty()) {
            return createdBatch.items.joinToString(separator = ", ") { item ->
                val note = item.preferenceNote?.takeIf { it.isNotBlank() }?.let { "; пожелание: $it" }.orEmpty()
                "${formatOrderItemName(item.itemName, item.selectedOption)} x${item.qty}$note — " +
                    formatCompactMoney(item.priceMinor * item.qty, item.currency)
            }
        }
        val itemIds = fallbackItems.map { it.itemId }.toSet()
        val itemNames =
            runCatching { guestMenuRepository.findItemNames(venueId, itemIds) }
                .getOrDefault(emptyMap())
        return fallbackItems.joinToString(separator = ", ") { item ->
            val name = itemNames[item.itemId] ?: "item#${item.itemId}"
            "$name x${item.qty}"
        }
    }

    private suspend fun resolveReplacementBeforeAcceptBatchFlag(
        venueId: Long,
        orderId: Long,
        batchId: Long,
    ): Boolean =
        try {
            val detail = venueOrdersRepository.loadOrderDetail(venueId = venueId, orderId = orderId) ?: return false
            val batch = detail.batches.firstOrNull { it.batchId == batchId } ?: return false
            isReplacementBeforeAcceptBatch(detail, batch)
        } catch (e: DatabaseUnavailableException) {
            false
        }

    private suspend fun resolveCurrentBotTab(
        chatId: Long,
        context: ResolvedChatContext,
    ): com.hookah.platform.backend.miniapp.guest.db.GuestTabModel? {
        val tableSession = resolveCurrentTableSession(chatId, context) ?: return null
        val personalTab =
            try {
                guestTabsRepository.ensurePersonalTab(
                    venueId = context.table.venueId,
                    tableSessionId = tableSession.id,
                    userId = context.userId,
                )
            } catch (e: CancellationException) {
                throw e
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return null
            }
        val userTabs =
            try {
                guestTabsRepository.listTabsForUser(
                    venueId = context.table.venueId,
                    tableSessionId = tableSession.id,
                    userId = context.userId,
                )
            } catch (e: CancellationException) {
                throw e
            } catch (e: DatabaseUnavailableException) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return null
            }
        val key = BotDraftCartKey(chatId = chatId, tableToken = context.table.tableToken)
        val selectedTabId = botSelectedTabIds[key]
        if (selectedTabId != null) {
            val selectedTab =
                userTabs.firstOrNull { tab ->
                    tab.id == selectedTabId && tab.status == "ACTIVE"
                }
            if (selectedTab != null) {
                return selectedTab
            }
            botSelectedTabIds.remove(key)
        }
        val activeSharedTabs =
            userTabs.filter { tab ->
                tab.status == "ACTIVE" && tab.type == "SHARED"
            }
        if (activeSharedTabs.isNotEmpty()) {
            var sharedWithActiveOrder: com.hookah.platform.backend.miniapp.guest.db.GuestTabModel? = null
            try {
                for (sharedTab in activeSharedTabs) {
                    val activeOrder =
                        ordersRepository.findActiveOrderSummaryForTab(
                            tableSessionId = tableSession.id,
                            tabId = sharedTab.id,
                        )
                    if (activeOrder != null) {
                        sharedWithActiveOrder = sharedTab
                        break
                    }
                }
            } catch (e: CancellationException) {
                throw e
            } catch (e: Exception) {
                enqueueMessage(chatId, "База недоступна, попробуйте позже.")
                return null
            }
            val restoredTab = sharedWithActiveOrder ?: activeSharedTabs.first()
            botSelectedTabIds[key] = restoredTab.id
            return restoredTab
        }
        return personalTab
    }

    private suspend fun upsertBotCartMessage(
        chatId: Long,
        key: BotDraftCartKey,
        text: String,
        replyMarkup: ReplyMarkup,
        sourceMessageId: Long?,
    ) {
        if (sourceMessageId != null) {
            outboxEnqueuer.enqueueEditMessageText(
                chatId = chatId,
                messageId = sourceMessageId,
                text = text,
                replyMarkup = replyMarkup,
            )
            botCartMessageIds[key] = sourceMessageId
            return
        }
        // Without callback source message id we can't reliably edit in place:
        // stale mapping may point to an outdated/deleted message.
        botCartMessageIds.remove(key)
        enqueueMessage(chatId, text, replyMarkup)
    }

    private suspend fun upsertBotMenuMessage(
        chatId: Long,
        tableToken: String,
        text: String,
        replyMarkup: ReplyMarkup,
        sourceMessageId: Long? = null,
    ) {
        val key = BotDraftCartKey(chatId = chatId, tableToken = tableToken)
        clearBotTransientScreens(chatId, key)
        val messageId =
            runCatching { apiClient.sendMessage(chatId, text, replyMarkup)?.messageId }
                .onFailure { logBestEffort("telegram direct menu send", it) }
                .getOrNull()
        if (messageId != null) {
            botMenuMessageIds[key] = messageId
            return
        }
        enqueueMessage(chatId, text, replyMarkup)
    }

    private suspend fun clearBotTransientScreens(
        chatId: Long,
        key: BotDraftCartKey,
    ) {
        botMenuMessageIds.remove(key)?.let { previousMessageId ->
            deleteMessageBestEffort(chatId, previousMessageId)
        }
        clearBotCartScreenMessages(chatId, key)
    }

    private suspend fun sendBotBookingScreen(
        chatId: Long,
        venueId: Long,
        text: String,
        replyMarkup: ReplyMarkup? = null,
    ) {
        clearBotBookingScreenMessages(chatId)
        val key = BotBookingScreenKey(chatId = chatId, venueId = venueId)
        val messageId =
            runCatching { apiClient.sendMessage(chatId, text, replyMarkup)?.messageId }
                .onFailure { logBestEffort("telegram direct booking send", it) }
                .getOrNull()
        if (messageId != null) {
            botBookingScreenMessageIds[key] = messageId
            return
        }
        enqueueMessage(chatId, text, replyMarkup)
    }

    private suspend fun clearBotBookingScreenMessages(chatId: Long) {
        val keysToClear =
            botBookingScreenMessageIds.keys
                .filter { key -> key.chatId == chatId }
        keysToClear.forEach { key ->
            botBookingScreenMessageIds.remove(key)?.let { messageId ->
                deleteMessageBestEffort(chatId, messageId)
            }
        }
    }

    private fun formatPrice(
        priceMinor: Long,
        currency: String,
    ): String {
        val amount = priceMinor.toDouble() / 100.0
        val symbol =
            when (currency.uppercase(Locale.ROOT)) {
                "RUB" -> "₽"
                "USD" -> "$"
                "EUR" -> "€"
                else -> currency.uppercase(Locale.ROOT)
            }
        return String.format(Locale.US, "%.2f %s", amount, symbol)
    }

    private fun formatCompactMoney(
        priceMinor: Long,
        currency: String,
    ): String {
        val normalizedCurrency = currency.uppercase(Locale.ROOT)
        if (normalizedCurrency == "RUB" && priceMinor % 100L == 0L) {
            return "%,d ₽".format(Locale.US, priceMinor / 100L).replace(',', ' ')
        }
        return formatPrice(priceMinor, currency)
    }

    private fun humanizeOrderStatus(rawStatus: String): String =
        when (rawStatus.uppercase(Locale.ROOT)) {
            "ACTIVE" -> "Принят"
            else -> "Принят"
        }

    private fun humanizeBillType(rawTabType: String?): String? =
        when (rawTabType?.uppercase(Locale.ROOT)) {
            "PERSONAL" -> "Личный"
            "SHARED" -> "Общий"
            else -> null
        }

    private fun humanizeBookingStatus(status: BookingStatus): String =
        when (status) {
            BookingStatus.PENDING -> "Ожидает подтверждения"
            BookingStatus.CONFIRMED -> "Подтверждена"
            BookingStatus.CHANGED -> "Изменена"
            BookingStatus.CANCELED -> "Отменена"
            BookingStatus.EXPIRED -> "Истекла"
            BookingStatus.NO_SHOW -> "Гость не пришёл"
            BookingStatus.SEATED -> "Гость пришёл"
        }

    private fun parseBotMenuCategoryData(data: String): Pair<Long, Int>? {
        return when {
            data.startsWith("bot_menu_back_category:") -> {
                val categoryId = data.removePrefix("bot_menu_back_category:").toLongOrNull() ?: return null
                categoryId to 0
            }
            data.startsWith("bot_menu_category_page:") -> {
                val payload = data.removePrefix("bot_menu_category_page:")
                val parts = payload.split(":", limit = 2)
                val categoryId = parts.getOrNull(0)?.toLongOrNull() ?: return null
                val page = parts.getOrNull(1)?.toIntOrNull() ?: return null
                categoryId to page.coerceAtLeast(0)
            }
            data.startsWith("bot_menu_category:") -> {
                val categoryId = data.removePrefix("bot_menu_category:").toLongOrNull() ?: return null
                categoryId to 0
            }
            else -> null
        }
    }

    private fun parseBotMenuItemData(data: String): Pair<Long, Long>? {
        val payload =
            when {
                data.startsWith("bot_menu_item_add_to_cart:") -> data.removePrefix("bot_menu_item_add_to_cart:")
                data.startsWith("bot_menu_item_add:") -> data.removePrefix("bot_menu_item_add:")
                data.startsWith("bot_menu_item_reorder:") -> data.removePrefix("bot_menu_item_reorder:")
                data.startsWith("bot_menu_item:") -> data.removePrefix("bot_menu_item:")
                else -> return null
            }
        val parts = payload.split(":", limit = 2)
        val categoryId = parts.getOrNull(0)?.toLongOrNull() ?: return null
        val itemId = parts.getOrNull(1)?.toLongOrNull() ?: return null
        return categoryId to itemId
    }

    private fun parseBotMenuItemOptionData(data: String): Triple<Long, Long, Long>? {
        if (!data.startsWith("bot_menu_item_option_add_to_cart:")) {
            return null
        }
        val payload = data.removePrefix("bot_menu_item_option_add_to_cart:")
        val parts = payload.split(":", limit = 3)
        val categoryId = parts.getOrNull(0)?.toLongOrNull() ?: return null
        val itemId = parts.getOrNull(1)?.toLongOrNull() ?: return null
        val optionId = parts.getOrNull(2)?.toLongOrNull() ?: return null
        return Triple(categoryId, itemId, optionId)
    }

    private fun parseBotMenuCartItemId(data: String): Long? {
        return when {
            data.startsWith("bot_menu_cart_inc:") -> data.removePrefix("bot_menu_cart_inc:").toLongOrNull()
            data.startsWith("bot_menu_cart_dec:") -> data.removePrefix("bot_menu_cart_dec:").toLongOrNull()
            data.startsWith("bot_menu_cart_remove:") -> data.removePrefix("bot_menu_cart_remove:").toLongOrNull()
            else -> null
        }
    }

    private fun addItemToBotDraftCart(
        chatId: Long,
        tableToken: String,
        tableSessionId: Long,
        tabId: Long,
        item: com.hookah.platform.backend.miniapp.guest.db.MenuItemModel,
        optionId: Long? = null,
        optionName: String? = null,
        optionPriceDeltaMinor: Long = 0L,
    ): Boolean {
        val key = BotDraftCartKey(chatId = chatId, tableToken = tableToken)
        val targetScope = BotDraftCartScope(tableSessionId = tableSessionId, tabId = tabId)
        val existingScope = botDraftCartScopes[key]
        if (existingScope != null && existingScope != targetScope) {
            return false
        }
        val cart = botDraftCarts.computeIfAbsent(key) { ConcurrentHashMap() }
        botDraftCartScopes[key] = targetScope
        botDraftCartSessionIds[key] = tableSessionId
        botSkippedGiftRules.remove(key)
        val existingEntry =
            cart.entries.firstOrNull { (_, existing) ->
                existing.itemId == item.id && existing.optionId == optionId
            }
        if (existingEntry != null) {
            val existing = existingEntry.value
            cart[existingEntry.key] = existing.copy(qty = existing.qty + 1)
            return true
        }
        val lineId = botDraftCartOrderSeq.incrementAndGet()
        val displayName =
            if (optionName.isNullOrBlank()) {
                item.name
            } else {
                "${item.name} · $optionName"
            }
        cart[lineId] =
            BotDraftCartItem(
                lineId = lineId,
                itemId = item.id,
                name = displayName,
                optionId = optionId,
                optionName = optionName,
                priceMinor = item.priceMinor + optionPriceDeltaMinor,
                currency = item.currency,
                qty = 1,
                orderSeq = lineId,
            )
        return true
    }

    private fun isBotDraftCartScopeMismatch(
        key: BotDraftCartKey,
        currentTab: com.hookah.platform.backend.miniapp.guest.db.GuestTabModel,
    ): Boolean {
        val scope = botDraftCartScopes[key] ?: return false
        return scope.tableSessionId != currentTab.tableSessionId || scope.tabId != currentTab.id
    }

    private suspend fun warnBotDraftCartScopeMismatch(chatId: Long) {
        enqueueMessage(
            chatId,
            "Корзина собрана для другого счёта. Очистите её и соберите заново для текущего счёта.",
        )
    }

    private suspend fun clearBotDraftCartIfScopedToDifferentTab(
        chatId: Long,
        tableToken: String,
        targetScope: BotDraftCartScope,
    ) {
        val key = BotDraftCartKey(chatId = chatId, tableToken = tableToken)
        val existingScope = botDraftCartScopes[key] ?: return
        val hasItems = botDraftCarts[key]?.isNotEmpty() == true
        if (hasItems && existingScope != targetScope) {
            clearBotDraftCart(chatId, tableToken)
            enqueueMessage(
                chatId,
                "Корзина была собрана для другого счёта, поэтому я очистил её. Соберите заказ " +
                    "заново для текущего счёта.",
            )
        }
    }

    private fun buildBotDraftCartOptionComment(items: List<BotDraftCartItem>): String? {
        val selectedOptions = items.filter { !it.optionName.isNullOrBlank() }
        if (selectedOptions.isEmpty()) {
            return null
        }
        return buildString {
            append("Выбранные вкусы: ")
            append(
                selectedOptions.joinToString("; ") { item ->
                    "${item.name} ×${item.qty}"
                },
            )
        }
    }

    private fun buildBotDraftCartSubmitComment(
        items: List<BotDraftCartItem>,
        guestComment: String?,
    ): String? {
        val optionComment = buildBotDraftCartOptionComment(items)
        val normalizedGuestComment = guestComment?.trim()?.takeIf { it.isNotBlank() }
        return when {
            normalizedGuestComment == null && optionComment == null -> null
            normalizedGuestComment != null && optionComment != null ->
                buildString {
                    append("Комментарий гостя: ")
                    append(normalizedGuestComment)
                    append("\n")
                    append(optionComment)
                }
            normalizedGuestComment != null -> normalizedGuestComment
            else -> optionComment
        }
    }

    private fun getBotDraftCartItems(
        chatId: Long,
        tableToken: String,
    ): List<BotDraftCartItem> {
        val key = BotDraftCartKey(chatId = chatId, tableToken = tableToken)
        return botDraftCarts[key]
            ?.values
            ?.sortedWith(
                compareBy<BotDraftCartItem> { it.orderSeq }
                    .thenBy { it.itemId },
            )
            .orEmpty()
    }

    private fun clearBotDraftCart(
        chatId: Long,
        tableToken: String,
    ) {
        val key = BotDraftCartKey(chatId = chatId, tableToken = tableToken)
        botDraftCarts.remove(key)
        botDraftCartComments.remove(key)
        botMenuMessageIds.remove(key)
        botCartMessageIds.remove(key)
        botCartScreenMessageIds.remove(key)
        botSelectedTabIds.remove(key)
        botDraftCartSessionIds.remove(key)
        botDraftCartScopes.remove(key)
        botGiftChoices.remove(key)
        botSkippedGiftRules.remove(key)
    }

    private fun clearAllBotDraftCartsForChat(chatId: Long) {
        botDraftCarts.keys.removeIf { it.chatId == chatId }
        botDraftCartComments.keys.removeIf { it.chatId == chatId }
        botMenuMessageIds.keys.removeIf { it.chatId == chatId }
        botCartMessageIds.keys.removeIf { it.chatId == chatId }
        botCartScreenMessageIds.keys.removeIf { it.chatId == chatId }
        botBookingScreenMessageIds.keys.removeIf { it.chatId == chatId }
        botBookingEditContexts.remove(chatId)
        botSelectedTabIds.keys.removeIf { it.chatId == chatId }
        botDraftCartSessionIds.keys.removeIf { it.chatId == chatId }
        botDraftCartScopes.keys.removeIf { it.chatId == chatId }
        botGiftChoices.keys.removeIf { it.chatId == chatId }
        botSkippedGiftRules.keys.removeIf { it.chatId == chatId }
        botJoinSharedAwaitingChats.remove(chatId)
    }

    private fun clearBotDraftStateForChatExceptTableToken(
        chatId: Long,
        tableToken: String,
    ) {
        val keysToClear =
            buildSet {
                addAll(botDraftCarts.keys)
                addAll(botDraftCartComments.keys)
                addAll(botMenuMessageIds.keys)
                addAll(botCartMessageIds.keys)
                addAll(botCartScreenMessageIds.keys)
                addAll(botSelectedTabIds.keys)
                addAll(botDraftCartSessionIds.keys)
                addAll(botDraftCartScopes.keys)
                addAll(botGiftChoices.keys)
                addAll(botSkippedGiftRules.keys)
            }
                .filter { key ->
                    key.chatId == chatId && key.tableToken != tableToken
                }
        keysToClear.forEach { key ->
            clearBotDraftCart(key.chatId, key.tableToken)
        }
    }

    private suspend fun clearBotCartScreenMessages(
        chatId: Long,
        key: BotDraftCartKey,
    ) {
        val messageIds = botCartScreenMessageIds.remove(key).orEmpty()
        messageIds.forEach { messageId ->
            deleteMessageBestEffort(chatId, messageId)
        }
    }

    private suspend fun sendBotCartScreenMessage(
        chatId: Long,
        key: BotDraftCartKey,
        text: String,
        replyMarkup: ReplyMarkup,
    ) {
        val messageId =
            runCatching { apiClient.sendMessage(chatId, text, replyMarkup)?.messageId }
                .onFailure { logBestEffort("telegram direct cart send", it) }
                .getOrNull()
        if (messageId != null) {
            botCartScreenMessageIds.compute(key) { _, existing -> (existing ?: emptyList()) + messageId }
            return
        }
        enqueueMessage(chatId, text, replyMarkup)
    }

    private suspend fun deleteMessageBestEffort(
        chatId: Long,
        messageId: Long,
    ) {
        runCatching {
            val payload: JsonObject =
                buildJsonObject {
                    put("chat_id", chatId)
                    put("message_id", messageId)
                }
            apiClient.callMethod("deleteMessage", payload)
        }.onFailure { logBestEffort("telegram cart message delete", it) }
    }

